module servant_timer
  #(parameter WIDTH = 16,
    parameter RESET_STRATEGY = "",
    parameter DIVIDER = 0)
  (input wire 	     i_clk,
   input wire 	     i_rst,
   output reg 	     o_irq,
   input wire [31:0] i_wb_dat,
   input wire 	     i_wb_we,
   input wire 	     i_wb_cyc,
   output reg [31:0] o_wb_dat);

   localparam HIGH = WIDTH-1-DIVIDER;

   reg [WIDTH-1:0]   mtime;
   reg signed [HIGH:0]      mtimecmp;

   wire signed [HIGH:0]     mtimeslice = mtime[WIDTH-1:DIVIDER];

   always @(mtimeslice) begin
      o_wb_dat = 32'd0;
      o_wb_dat[HIGH:0] = mtimeslice;
   end

   always @(posedge i_clk) begin
      if (i_wb_cyc & i_wb_we)
	mtimecmp <= i_wb_dat[HIGH:0];
      mtime <= mtime + 'd1;
      o_irq <= (mtimeslice - mtimecmp >= 0);
      if (RESET_STRATEGY != "NONE")
	if (i_rst) begin
	   mtime <= 0;
	   mtimecmp <= 0;
	end
   end
endmodule

module servant_ice40_cm36 (
    input  wire i_clk,
    output wire o_led
);

  parameter memfile = "blinky.hex";
  parameter memsize = 7168;

  wire wb_clk;
  reg  wb_rst;

  /* iCE40 CM36 has no PLL. Drive everything from the external clock. */
  assign wb_clk = i_clk;

  /* Board has no button that can be used for reset, but blinky doesn't
   * work at all if the reset isn't enabled for at least 25 clocks.
   *
   * This will generate a reset signal at power on.
   */
  reg [7:0] rst_cnt = '0;

  always @(posedge i_clk) begin
    if (rst_cnt < 255) begin
      rst_cnt <= rst_cnt + 1;
      wb_rst  <= 1;
    end else begin
      wb_rst <= 0;
    end
  end

  servant #(
      .memfile(memfile),
      .memsize(memsize)
  ) servant (
      .wb_clk(wb_clk),
      .wb_rst(wb_rst),
      .q     (o_led)
  );

endmodule

