module servant_pf (
	input  wire i_clk,
	input  wire resetb,
	output wire o_led1,
	output wire o_led2,
	output wire o_led3 = 1'b0,
	output wire o_led4 = 1'b0,
	output wire o_led5 = 1'b0,
	output wire o_led6 = 1'b0,
	output wire o_led7 = 1'b0,
	output wire o_led8 = 1'b0,
	output wire o_uart_tx);

	parameter memfile = "zephyr_hello.hex";
	parameter memsize = 8192;

	wire	clk;
	wire	rst;
	wire	q;
	wire	CLKINT_0_Y;
	reg		heartbeat;

	CLKINT CLKINT_0(
		.A (i_clk),
		.Y (CLKINT_0_Y)
	);

	servant_pf_clock_gen #(
		.refclk(50),
		.frequency(32)
	) clock_gen (
		.i_clk (CLKINT_0_Y),
		.o_clk (clk)
	);

	servant #(
		.memfile (memfile),
		.memsize (memsize)
	) servant (
		.wb_clk	(clk),
		.wb_rst	(rst),
		.q		(q)
	);

	// heartbeat LED
	reg [$clog2(32000000)-1:0] count = 0;
	always @(posedge clk) begin
		if (rst) begin
			count <= 0;
			heartbeat <= 0;
		end else
			count <= count + 1;
		if (count == 32000000-1) begin
			heartbeat <= !heartbeat;
			count <= 0;
		end
	end

	assign rst = ~resetb;
	assign o_led1 = q;
	assign o_led2 = heartbeat;
	assign o_uart_tx = q;

endmodule

module servax_clock_gen
  (input wire  i_clk,
   output wire o_clk,
   output reg  o_rst);

   wire   locked;
   reg 	  locked_r;    


    DCM_SP #(
      .CLKFX_DIVIDE(25),   // Can be any integer from 1 to 32
      .CLKFX_MULTIPLY(8), // Can be any integer from 2 to 32
      .CLKIN_PERIOD(20.0)  //50Mhz
    ) 
    DCM_SP_inst (
      .CLKFX(o_clk),   // DCM CLK synthesis out (M/D)
      .CLKFX180(), // 180 degree CLK synthesis out
      .LOCKED(locked), // DCM LOCK status output
      .STATUS(), // 8-bit DCM status bits output
      .CLKFB(),   // DCM clock feedback
      .CLKIN(i_clk),   // Clock input
      .RST(1'b0)        // DCM asynchronous reset input
   );

   always @(posedge o_clk) begin
      locked_r <= locked;
      o_rst  <= !locked_r;
   end

endmodule

module servant
