module prim_clock_gating #(
  parameter bit NoFpgaGate = 1'b0,
  parameter bit FpgaBufGlobal = 1'b1
) (
  input        clk_i,
  input        en_i,
  input        test_en_i,
  output logic clk_o
);

  if (NoFpgaGate) begin : gen_no_gate
    assign clk_o = clk_i;
  end else begin : gen_gate
    if (FpgaBufGlobal) begin : gen_bufgce
      // By default, we use BUFG(CE)s, i.e., global clock buffers (with enable input).
      // These resources are scarce (32 in monolithic 7 series devices) and under some
      // circumstances cannot be cascaded. They should especially be used for (gating)
      // clocks that span big parts of the design/multiple clock regions.
      BUFGCE #(
        .SIM_DEVICE("7SERIES")
      ) u_bufgce (
        .I (clk_i),
        .CE(en_i | test_en_i),
        .O (clk_o)
      );
    end else begin : gen_bufhce
      // The BUFH(CE) is a horizontal or local clock buffer (with enable input). Every clock
      // region has 12 of these buffers. They should be used for (gating) clocks that are
      // being used locally.
      BUFHCE u_bufhce (
        .I (clk_i),
        .CE(en_i | test_en_i),
        .O (clk_o)
      );
    end
  end



endmodule

module prim_alert_rxtx_async_assert_fpv
  import prim_mubi_pkg::mubi4_t;
(
  input        clk_i,
  input        rst_ni,
  // for sigint error and skew injection only
  input        ping_err_pi,
  input        ping_err_ni,
  input [1:0]  ping_skew_i,
  input        ack_err_pi,
  input        ack_err_ni,
  input [1:0]  ack_skew_i,
  input        alert_err_pi,
  input        alert_err_ni,
  input [1:0]  alert_skew_i,
  // normal I/Os
  input        alert_test_i,
  input  mubi4_t init_trig_i,
  input        alert_req_i,
  input        alert_ack_o,
  input        alert_state_o,
  input        ping_req_i,
  input        ping_ok_o,
  input        integ_fail_o,
  input        alert_o
);

  import prim_mubi_pkg::mubi4_test_true_strict;

  logic error_present;
  assign error_present = ping_err_pi  | ping_err_ni |
                         ack_err_pi   | ack_err_ni  |
                         alert_err_pi | alert_err_ni;

  logic init_pending;
  assign init_pending = mubi4_test_true_strict(init_trig_i) ||
                        prim_alert_rxtx_async_tb.i_prim_alert_receiver.state_q inside {
                        prim_alert_rxtx_async_tb.i_prim_alert_receiver.InitReq,
                        prim_alert_rxtx_async_tb.i_prim_alert_receiver.InitAckWait};

  logic sender_is_idle, receiver_is_idle, sender_is_pinging;
  assign sender_is_idle = i_prim_alert_sender.state_q == i_prim_alert_sender.Idle;
  assign receiver_is_idle = i_prim_alert_receiver.state_q == i_prim_alert_receiver.Idle;
  assign sender_is_pinging = i_prim_alert_sender.state_q inside
                             {i_prim_alert_sender.PingHsPhase1, i_prim_alert_sender.PingHsPhase2};

  // A signal that is true if the alert sender is sending an alert (p & !n)
  logic alert_from_sender;
  assign alert_from_sender = prim_alert_rxtx_async_tb.alert_tx_out.alert_p &&
                             !prim_alert_rxtx_async_tb.alert_tx_out.alert_n;

  // used to check that an error has never occurred so far
  // this is used to check the handshake below. the handshake can lock up
  // the protocol FSMs causing the handshake to never complete.
  // note that this will block any ping messages and hence it can be
  // eventually detected by the alert handler.
  logic error_setreg_d, error_setreg_q;
  assign error_setreg_d = error_present | error_setreg_q;

  always_ff @(posedge clk_i or negedge rst_ni) begin : p_reg
    if (!rst_ni) begin
      error_setreg_q <= 1'b0;
    end else begin
      error_setreg_q <= error_setreg_d;
    end
  end

  // Note: we can only detect sigint errors where one wire is flipped.
  `ASSUME_FPV(PingErrorsAreOH_M,  $onehot0({ping_err_pi, ping_err_ni})  )
  `ASSUME_FPV(AckErrorsAreOH_M,   $onehot0({ack_err_pi, ack_err_ni})    )
  `ASSUME_FPV(AlertErrorsAreOH_M, $onehot0({alert_err_pi, alert_err_ni}))

  // ping will stay high until ping ok received, then it must be deasserted
  // TODO: this excludes the case where no ping ok will be returned due to an error
  `ASSUME_FPV(PingDeassert_M, ping_req_i && ping_ok_o |=> !ping_req_i)
  `ASSUME_FPV(PingEn_M, $rose(ping_req_i) |-> ping_req_i throughout
      (ping_ok_o || error_present)[->1] ##1 $fell(ping_req_i))

  // Note: the sequence lengths of the handshake and the following properties needs to
  // be parameterized accordingly if different clock ratios are to be used here.
  // TODO: tighten bounds if possible
  sequence FullHandshake_S;
    $rose(prim_alert_rxtx_async_tb.alert_pd)   ##[3:6]
    $rose(prim_alert_rxtx_async_tb.ack_pd)     &&
    $stable(prim_alert_rxtx_async_tb.alert_pd) ##[3:6]
    $fell(prim_alert_rxtx_async_tb.alert_pd)   &&
    $stable(prim_alert_rxtx_async_tb.ack_pd)   ##[3:6]
    $fell(prim_alert_rxtx_async_tb.ack_pd)     &&
    $stable(prim_alert_rxtx_async_tb.alert_pd);
  endsequence

  // note: injected errors may lockup the FSMs, and hence the full HS can
  // only take place if both FSMs are in a good state
  `ASSERT(PingHs_A, ##1 $changed(prim_alert_rxtx_async_tb.ping_pd) &&
      sender_is_idle && receiver_is_idle |-> ##[0:5] FullHandshake_S,
      clk_i, !rst_ni || error_setreg_q || init_pending)
  `ASSERT(AlertHs_A, alert_req_i &&
      sender_is_idle && receiver_is_idle |-> ##[0:5] FullHandshake_S,
      clk_i, !rst_ni || error_setreg_q || init_pending)
  `ASSERT(AlertTestHs_A, alert_test_i &&
      sender_is_idle && receiver_is_idle |-> ##[0:5] FullHandshake_S,
      clk_i, !rst_ni || error_setreg_q || init_pending)
  // Make sure we eventually get an ACK
  `ASSERT(AlertReqAck_A, alert_req_i &&
      sender_is_idle && receiver_is_idle |-> strong(##[1:$] alert_ack_o),
      clk_i, !rst_ni || error_setreg_q || init_pending)

  // Transmission of pings
  //
  // Check that if we tell the receiver to request a ping then it will send one and get a response
  // in a bounded time. Note that this is considering the "good case": we assume that we aren't
  // injecting errors or skews that will break the signal integrity.
  //
  // This bound is relatively large as, in the worst case, we need to resolve staggered differential
  // signal patterns on all three differential channels.
  //
  // Note 0: The ping sent from the alert receiver is just a single cycle long. For this property,
  // we aren't interested in the sort of clock jitter that might eat the ping signal (a pulse of a
  // channel of ping_skew_i at just the wrong time). If that happens in the real chip, it probably
  // shows an attack and this will behave like a ping that doesn't get a response. This causes a
  // timer in the alert handler that requested the ping to send an alert out itself.
  //
  // Note 1: The complete transmission of pings only happens when no ping handshake is in progress,
  // so we only allow the property to start when the sender isn't in a ping handshake FSM state.
  //
  // Note 2: The receiver gives up on a ping request if it receives an alert (this is strong
  // evidence that alerts can come through, so it doesn't really need to do the ping at all!) To see
  // the ping handshake go through, we constrain things to ensure this doesn't happen.
  `ASSERT(AlertPingOk_A,
          !sender_is_pinging && $rose(ping_req_i) |-> ##[1:23] ping_ok_o,
          clk_i,
          (!rst_ni || error_setreg_q || init_pending || alert_from_sender ||
           $changed(ping_skew_i, @clk_i) || ^ping_skew_i ||
           ack_skew_i))

  `ASSERT(AlertPingIgnored_A,
          sender_is_pinging && $rose(ping_req_i) |-> ping_ok_o == 0 throughout ping_req_i[->1],
          clk_i, !rst_ni || error_setreg_q)

  // transmission of first alert assertion (no ping collision)
  `ASSERT(AlertCheck0_A,
      !ping_req_i [*10] ##1 ($rose(alert_req_i) || $rose(alert_test_i)) && sender_is_idle |->
      ##[3:5] alert_o,
      clk_i, !rst_ni || ping_req_i || error_setreg_q || init_pending || alert_skew_i || ack_skew_i)
  // eventual transmission of alerts in the general case which can include continous ping
  // collisions
  `ASSERT(AlertCheck1_A,
      alert_req_i || alert_test_i |-> strong(##[1:$] sender_is_idle ##[3:5] alert_o),
      clk_i, !rst_ni || error_setreg_q ||
      prim_alert_rxtx_async_tb.i_prim_alert_sender.alert_clr || init_pending)

  // basic liveness of FSMs in case no errors are present
  `ASSERT(FsmLivenessSender_A,
      !error_present [*2] ##1 !error_present && !sender_is_idle |->
      strong(##[1:$] sender_is_idle),
      clk_i, !rst_ni || error_present || init_pending)
  `ASSERT(FsmLivenessReceiver_A,
      !error_present [*2] ##1 !error_present && receiver_is_idle |->
      strong(##[1:$] receiver_is_idle),
      clk_i, !rst_ni || error_present || init_pending)

  // check that the in-band reset moves sender FSM into Idle state.
  `ASSERT(InBandInitFromReceiverToSender_A,
      mubi4_test_true_strict(init_trig_i)
      |->
      ##[1:30] sender_is_idle,
      clk_i, !rst_ni || error_present)

endmodule

module prim_fifo_sync_assert_fpv #(
  // can be desabled for deeper FIFOs
  parameter bit EnableDataCheck = 1'b1,
  parameter int unsigned Width = 16,
  parameter bit Pass = 1'b1,
  parameter int unsigned Depth = 4,
  localparam int unsigned DepthWNorm = $clog2(Depth+1),
  localparam int unsigned DepthW = (DepthWNorm == 0) ? 1 : DepthWNorm
) (
  input              clk_i,
  input              rst_ni,
  input              clr_i,
  input              wvalid_i,
  input              wready_o,
  input [Width-1:0]  wdata_i,
  input              rvalid_o,
  input              rready_i,
  input [Width-1:0]  rdata_o,
  input              full_o,
  input [DepthW-1:0] depth_o,
  input              err_o
);

  localparam bit [DepthW+2:0] WideOne = (DepthW + 3)'(1'b1);
  localparam int unsigned PtrW = prim_util_pkg::vbits(Depth);

  /////////////////
  // Assumptions //
  /////////////////

  // no need to consider all possible input words
  // 2-3 different values suffice
  `ASSUME(WdataValues_M, wdata_i inside {Width'(1'b0), Width'(1'b1), {Width{1'b1}}}, clk_i, !rst_ni)

  ////////////////////////////////
  // Data and Depth Value Check //
  ////////////////////////////////

   if (EnableDataCheck && Depth > 0) begin : gen_data_check

    logic [DepthW+2:0] ref_depth;
    logic [Width-1:0]  ref_rdata;

    // no pointers needed in this case
    if (Depth == 1) begin : gen_no_ptrs

      logic [Width-1:0]  fifo;
      logic [DepthW+2:0] wptr, rptr;

      // this only models the data flow, since the control logic is tested below
      always_ff @(posedge clk_i or negedge rst_ni) begin : p_fifo_model
        if (!rst_ni) begin
          ref_depth <= 0;
        end else begin
          if (clr_i) begin
            ref_depth <= 0;
          end else begin
            if (wvalid_i && wready_o && rvalid_o && rready_i) begin
              fifo <= wdata_i;
            end else if (wvalid_i && wready_o) begin
              fifo <= wdata_i;
              ref_depth <= ref_depth + (DepthW+2)'(1);
            end else if (rvalid_o && rready_i) begin
              ref_depth <= ref_depth - (DepthW+2)'(1);
            end
          end
        end
      end

      if (Pass) begin : gen_pass
        assign ref_rdata = (ref_depth == 0) ? wdata_i : fifo;
      end else begin : gen_no_pass
        assign ref_rdata = fifo;
      end

    // general case
    end else begin : gen_ptrs

      logic [Width-1:0]  fifo [Depth];
      logic [DepthW+2:0] wptr, rptr;

      // implements (++val) mod Depth
      function automatic logic [DepthW+2:0] modinc(logic [DepthW+2:0] val, int modval);
        if (val == Depth-1) return 0;
        else                return val + WideOne;
      endfunction

      // this only models the data flow, since the control logic is tested below
      always_ff @(posedge clk_i or negedge rst_ni) begin : p_fifo_model
        if (!rst_ni) begin
          wptr      <= 0;
          rptr      <= 0;
          ref_depth <= 0;
        end else begin
          if (clr_i) begin
            wptr      <= 0;
            rptr      <= 0;
            ref_depth <= 0;
          end else begin
            if (wvalid_i && wready_o && rvalid_o && rready_i) begin
              fifo[wptr[PtrW-1:0]] <= wdata_i;
              wptr <= modinc(wptr, Depth);
              rptr <= modinc(rptr, Depth);
            end else if (wvalid_i && wready_o) begin
              fifo[wptr[PtrW-1:0]] <= wdata_i;
              wptr <= modinc(wptr, Depth);
              ref_depth <= ref_depth + WideOne;
            end else if (rvalid_o && rready_i) begin
              rptr <= modinc(rptr, Depth);
              ref_depth <= ref_depth - WideOne;
            end
          end
        end
      end

      if (Pass) begin : gen_pass
        assign ref_rdata = (ref_depth == 0) ? wdata_i : fifo[rptr[PtrW-1:0]];
      end else begin : gen_no_pass
        assign ref_rdata = fifo[rptr[PtrW-1:0]];
      end

    end

    // check the data
    `ASSERT(DataCheck_A, rvalid_o |-> rdata_o == ref_rdata)
    // check the depth
    `ASSERT(DepthCheck_A, ref_depth == depth_o)

  end

  ////////////////////////
  // Forward Assertions //
  ////////////////////////

  // The full_o port should be high iff the depth is maximal.
  `ASSERT(FullIffFullDepth_A, (depth_o == Depth) <-> (full_o))

  // assert depth of FIFO
  `ASSERT(Depth_A, depth_o <= Depth)
  // if we clear the FIFO, it must be empty in the next cycle
  `ASSERT(CheckClrDepth_A, clr_i |=> depth_o == 0)
  // check write on full
  `ASSERT(WriteFull_A, depth_o == Depth && wvalid_i && !rready_i |=> depth_o == $past(depth_o),
      clk_i, !rst_ni || clr_i)
  // read empty
  `ASSERT(ReadEmpty_A, depth_o == 0 && rready_i && !wvalid_i |=> depth_o == 0,
      clk_i, !rst_ni || clr_i)

  // this is unreachable in depth 1 no-pass through mode
  if (Depth == 1 && Pass) begin : gen_d1_passthru
    // check simultaneous write and read
    `ASSERT(WriteAndRead_A,
        wready_o && wvalid_i && rvalid_o && rready_i |=> depth_o == $past(depth_o),
        clk_i, !rst_ni || clr_i)
  end

  if (Depth == 0) begin : gen_depth0
    // if there is no register, the FIFO is per definition pass-through
    `ASSERT_INIT(ZeroDepthNeedsPass_A, Pass == 1)
    // depth must remain zero
    `ASSERT(DepthAlwaysZero_A, depth_o == 0)
    // data is just passed through
    `ASSERT(DataPassThru_A, wdata_i == rdata_o)
    // FIFO is ready if downstream logic is ready
    `ASSERT(Wready_A, rready_i == wready_o)
    // valid input is valid output
    `ASSERT(Rvalid_A, rvalid_o == wvalid_i)
    // ensure full coverage
    `ASSERT(UnusedClr_A, prim_fifo_sync.gen_passthru_fifo.unused_clr == clr_i)
  end else begin : gen_depth_gt0
    // check wready

    // The wready_o signal should be high (saying that we can accept an item in the fifo) if the
    // FIFO is not currently full, which can be checked my seeing that depth_o < Depth. This
    // property is delayed for a single cycle after coming out of reset (because of an under_rst
    // signal that gets cleared on the first clock afterwards).
    `ASSERT(Wready_A, 1 |=> depth_o < Depth -> wready_o)
    // check rvalid
    `ASSERT(Rvalid_A, depth_o > 0 |-> rvalid_o)
    // check write only
    `ASSERT(WriteOnly_A, wvalid_i && wready_o && !rready_i && depth_o < Depth |=>
        depth_o == $past(depth_o) + 1, clk_i, !rst_ni || clr_i)
    // check read only
    `ASSERT(ReadOnly_A, !wvalid_i && rready_i && rvalid_o && depth_o > 0 |=>
      depth_o == $past(depth_o) - 1, clk_i, !rst_ni || clr_i)
  end

  if (Pass) begin : gen_pass_fwd
    // if we clear the FIFO, it must be empty in the next cycle
    // but we may also get a pass through
    `ASSERT(CheckClrValid_A, clr_i |=> wvalid_i == rvalid_o)
  end else begin : gen_nopass_fwd
    // if we clear the FIFO, it must be empty in the next cycle
    `ASSERT(CheckClrValid_A, clr_i |=> !rvalid_o)
  end

  /////////////////////////
  // Backward Assertions //
  /////////////////////////

  if (Pass) begin : gen_pass_bkwd
    // there is still space in the FIFO or downstream logic is ready
    `ASSERT(WreadySpacekBkwd_A, wready_o |-> depth_o < Depth || rready_i)
    // elements ready to be read or upstream data is valid
    `ASSERT(RvalidElemskBkwd_A, rvalid_o |-> depth_o > 0 || wvalid_i)
  end else begin : gen_nopass_bkwd
    // there is still space in the FIFO
    `ASSERT(WreadySpacekBkwd_A, wready_o |-> depth_o < Depth)
    // elements ready to be read
    `ASSERT(RvalidElemskBkwd_A, rvalid_o |-> depth_o > 0)
  end

  // If the wready_o signal is not high, the FIFO should be full. As with Wready_A, this property is
  // delayed by a cycle after coming out of reset, to handle the clearing of the under_rst signal.
  `ASSERT(WreadyNoSpaceBkwd_A, 1 |=> !wready_o -> depth_o == Depth)
  // elements ready to be read
  `ASSERT(RvalidNoElemskBkwd_A, !rvalid_o |-> depth_o == 0)

  // The err_o signal should never go high. This isn't supposed to be triggerable without fault
  // injection (which isn't modelled in FPV so the output should be constant zero).
  `ASSERT(NoErrSignal_A, !err_o)

endmodule

module for prim_fifo_sram_async

module prim_fifo_async_sram_adapter_tb #(
  parameter int unsigned Width = 32,
  parameter int unsigned Depth = 16,

  parameter int unsigned FpgaSram = 0 // Use FF based
) (
  input clk_wr_i,
  input clk_rd_i,

  input rst_ni,

  input                    wvalid_i,
  output logic             wready_o,
  input        [Width-1:0] wdata_i,

  output logic             rvalid_o,
  input                    rready_i,
  output logic [Width-1:0] rdata_o
);

  localparam int unsigned       SramAw = 7;
  localparam int unsigned       SramDw = 32;
  localparam logic [SramAw-1:0] SramBaseAddr = 'h 30;

  logic              w_sram_req;
  logic              w_sram_gnt;
  logic              w_sram_write;
  logic [SramAw-1:0] w_sram_addr;
  logic [SramDw-1:0] w_sram_wdata;
  logic [SramDw-1:0] w_sram_wmask;
  logic              w_sram_rvalid; // not used
  logic [SramDw-1:0] w_sram_rdata;  // not used
  logic [1:0]        w_sram_rerror; // not used

  logic              r_sram_req;
  logic              r_sram_gnt;
  logic              r_sram_write;
  logic [SramAw-1:0] r_sram_addr;
  logic [SramDw-1:0] r_sram_wdata; // not used
  logic [SramDw-1:0] r_sram_wmask; // not used
  logic              r_sram_rvalid;
  logic [SramDw-1:0] r_sram_rdata;
  logic [1:0]        r_sram_rerror;

  prim_fifo_async_sram_adapter #(
    .Width (Width),
    .Depth (Depth),

    .SramAw (SramAw), // TODO: random with constraint
    .SramDw (SramDw), // TODO: random with constraint

    .SramBaseAddr(SramBaseAddr) // TODO: random?
  ) dut (
    .clk_wr_i,
    .rst_wr_ni (rst_ni),
    .clk_rd_i,
    .rst_rd_ni (rst_ni),

    .wvalid_i,
    .wready_o,
    .wdata_i,

    .wdepth_o (),

    .rvalid_o,
    .rready_i,
    .rdata_o,

    .rdepth_o (),

    // Sram Interface
    .w_sram_req_o   (w_sram_req   ),
    .w_sram_gnt_i   (w_sram_gnt   ),
    .w_sram_write_o (w_sram_write ),
    .w_sram_addr_o  (w_sram_addr  ),
    .w_sram_wdata_o (w_sram_wdata ),
    .w_sram_wmask_o (w_sram_wmask ),
    .w_sram_rvalid_i(w_sram_rvalid), // not used
    .w_sram_rdata_i (w_sram_rdata ),  // not used
    .w_sram_rerror_i(w_sram_rerror), // not used

     // Read SRAM port
    .r_sram_req_o   (r_sram_req   ),
    .r_sram_gnt_i   (r_sram_gnt   ),
    .r_sram_write_o (r_sram_write ),
    .r_sram_addr_o  (r_sram_addr  ),
    .r_sram_wdata_o (r_sram_wdata ), // not used
    .r_sram_wmask_o (r_sram_wmask ), // not used
    .r_sram_rvalid_i(r_sram_rvalid),
    .r_sram_rdata_i (r_sram_rdata ),
    .r_sram_rerror_i(r_sram_rerror),

    .r_full_o(),

    .r_notempty_o(),

    .w_full_o()
  );

if (FpgaSram == 1) begin : g_sram_fpga
  // FPV looks like does not like the style of ram_2p.
  prim_ram_2p #(
    .Depth           (2**SramAw),
    .Width           (SramDw),
    .DataBitsPerMask (1)
  ) u_sram (
    .clk_a_i  (clk_wr_i),
    .clk_b_i  (clk_rd_i),

    .a_req_i   (w_sram_req   ),
    .a_write_i (w_sram_write ),
    .a_addr_i  (w_sram_addr  ),
    .a_wdata_i (w_sram_wdata ),
    .a_wmask_i (w_sram_wmask ),
    .a_rdata_o (w_sram_rdata ),

    .b_req_i   (r_sram_req   ),
    .b_write_i (r_sram_write ),
    .b_addr_i  (r_sram_addr  ),
    .b_wdata_i (r_sram_wdata ),
    .b_wmask_i (r_sram_wmask ),
    .b_rdata_o (r_sram_rdata ),

    .cfg_i     ('0),
    .cfg_rsp_o ()
  );
end else begin : g_sram_ff
  logic [SramDw-1:0] mem [2**SramAw];

  always_ff @(posedge clk_wr_i) begin
    if (w_sram_req && w_sram_write) begin
      for (int unsigned i = 0; i < SramDw ; i++) begin
        if (w_sram_wmask[i]) mem[w_sram_addr][i] <= w_sram_wdata[i];
      end // for
    end // if
  end

  always_ff @(posedge clk_rd_i) begin
    if (r_sram_req && !r_sram_write) begin
      r_sram_rdata <= mem[r_sram_addr];
    end
  end
end // !FpgaSram

  assign w_sram_gnt = w_sram_req;

  always_ff @(posedge clk_wr_i) begin
    w_sram_rvalid <= w_sram_req && !w_sram_write;
  end

  assign w_sram_rerror = '0;

  assign r_sram_gnt = r_sram_req;

  always_ff @(posedge clk_rd_i) begin
    r_sram_rvalid <= r_sram_req && !r_sram_write;
  end

  assign r_sram_rerror = '0;

  `ASSUME_FPV(WdataBins_M,
              wvalid_i |-> wdata_i inside {
                32'h DEAD_BEEF, 32'h5A5A_A5A5, 32'h 1234_5678
                },
              clk_wr_i, !rst_ni)

`ifdef FPV_ON
  logic [Width-1:0] storage [Depth];
  logic [Width-1:0] rdata;
  logic [$clog2(Depth)-1:0] wptr, rptr;
  logic wack, rack;

  assign wack = wvalid_i && wready_o;
  assign rack = rvalid_o && rready_i;

  always_ff @(posedge clk_wr_i or negedge rst_ni) begin
    if (!rst_ni) wptr <= '0;
    else if (wack) wptr <= wptr+1;
  end
  always_ff @(posedge clk_rd_i or negedge rst_ni) begin
    if (!rst_ni) rptr <= '0;
    else if (rack) rptr <= rptr+1;
  end

  always_ff @(posedge clk_wr_i or negedge rst_ni) begin
    if (!rst_ni) storage <= '{default:'0};
    else if (wack) begin
      storage[wptr] <= wdata_i;
    end
  end

  assign rdata = storage[rptr];

  `ASSERT(DataIntegrityCheck_A,
          rack |-> rdata_o == rdata,
          clk_rd_i, !rst_ni)
`endif // FPV_ON

endmodule

module for alert sender/receiver pair. Intended to use with
// a formal tool.

module prim_alert_rxtx_fatal_tb
  import prim_alert_pkg::*;
  import prim_mubi_pkg::mubi4_t;
(
  input        clk_i,
  input        rst_ni,
  // for sigint error injection only
  input        ping_err_pi,
  input        ping_err_ni,
  input        ack_err_pi,
  input        ack_err_ni,
  input        alert_err_pi,
  input        alert_err_ni,
  // normal I/Os
  input        alert_test_i,
  input        alert_req_i,
  input  mubi4_t init_trig_i,
  input        ping_req_i,
  output logic alert_ack_o,
  output logic alert_state_o,
  output logic ping_ok_o,
  output logic integ_fail_o,
  output logic alert_o
);

  // synchronous case
  localparam bit AsyncOn = 1'b0;
  localparam bit IsFatal = 1'b1;

  localparam int unsigned SkewCycles = 1;

  alert_rx_t alert_rx_out, alert_rx_in;
  alert_tx_t alert_tx_out, alert_tx_in;

  assign alert_rx_in.ping_p = alert_rx_out.ping_p ^ ping_err_pi;
  assign alert_rx_in.ping_n = alert_rx_out.ping_n ^ ping_err_ni;
  assign alert_rx_in.ack_p  = alert_rx_out.ack_p  ^ ack_err_pi;
  assign alert_rx_in.ack_n  = alert_rx_out.ack_n  ^ ack_err_ni;

  assign alert_tx_in.alert_p = alert_tx_out.alert_p ^ alert_err_pi;
  assign alert_tx_in.alert_n = alert_tx_out.alert_n ^ alert_err_ni;

  prim_alert_sender #(
    .AsyncOn    ( AsyncOn    ),
    .SkewCycles ( SkewCycles ),
    .IsFatal    ( IsFatal    )
  ) i_prim_alert_sender (
    .clk_i,
    .rst_ni,
    .alert_test_i,
    .alert_req_i,
    .alert_ack_o,
    .alert_state_o,
    .alert_rx_i ( alert_rx_in  ),
    .alert_tx_o ( alert_tx_out )
  );

  prim_alert_receiver #(
    .AsyncOn    ( AsyncOn    ),
    .SkewCycles ( SkewCycles )
  ) i_prim_alert_receiver (
    .clk_i,
    .rst_ni,
    .init_trig_i,
    .ping_req_i,
    .ping_ok_o,
    .integ_fail_o,
    .alert_o,
    .alert_rx_o ( alert_rx_out ),
    .alert_tx_i ( alert_tx_in  )
  );

endmodule

module for prim_keccak. Intended to be used with a formal tool.

module prim_keccak_tb #(
  parameter int Width = 1600
) (
  input                    clk_i,
  input                    rst_ni,
  input                    valid_i,
  input        [Width-1:0] state_i,
  output logic             done_o,
  output logic [Width-1:0] state_o
);

  localparam int W        = Width/25;
  localparam int L        = $clog2(W);
  localparam int NumRound = 12 + 2*L; // Keccak-f only
  localparam int RndW     = $clog2(NumRound+1);
  logic [RndW-1:0] round;
  logic active;
  logic [Width-1:0] state, state_d;

  always_ff @(posedge clk_i or negedge rst_ni) begin
    if (!rst_ni) state <= '0;
    else if (valid_i) state <= state_i;
    else if (active)  state <= state_d;
  end

  always_ff @(posedge clk_i or negedge rst_ni) begin
    if (!rst_ni) round <= '0;
    else if (valid_i) round <= '0;
    else if (active)  round <= round + 1'b 1;
  end

  always_ff @(posedge clk_i or negedge rst_ni) begin
    if (!rst_ni) active <= 1'b 0;
    else if (valid_i) active <= 1'b 1;
    else if (round == (NumRound -1)) active <= 1'b 0;
  end

  assign done_o = (round == NumRound);
  assign state_o = state;

  prim_keccak #(
    .Width (Width)
  ) u_keccak (
    .rnd_i  (round),
    .s_i    (state),
    .s_o    (state_d)
  );


  `ASSUME_FPV(ValidSequence_A, ##1 valid_i |=> !valid_i)
  `ASSUME_FPV(ValidValid_A, active |-> !valid_i)

  // Test with value 0
  logic [1599:0] data_0 ;
  always_comb begin
    data_0 = '0;
    // SHA3-256 ==> r : 1088
    data_0[1087] = 1'b 1;
    data_0[2:0] = 3'b 110;
  end
  logic [255:0] digest_0;
  // Big-Endian a7ffc6f8bf1ed76651c14756a061d662f580ff4de43b49fa82d80a4b80f8434a
  assign digest_0 = 256'h 4a43_f880_4b0a_d882_fa49_3be4_4dff_80f5_62d6_61a0_5647_c151_66d7_1ebf_f8c6_ffa7;
  `ASSUME_FPV(Data0TestSHA3_256_A, state_i == data_0)
  `ASSERT(DigestForData0TestSHA3_256_A, done_o |-> state_o[255:0] == digest_0)

endmodule

