module prim_packer #(
  parameter int unsigned InW  = 32,
  parameter int unsigned OutW = 32,

  // If 1, The input/output are byte granularity
  parameter int HintByteData = 0,

  // Turn on protect against FI for the pos variable
  parameter bit EnProtection = 1'b 0
) (
  input clk_i ,
  input rst_ni,

  input                   valid_i,
  input        [InW-1:0]  data_i,
  input        [InW-1:0]  mask_i,
  output                  ready_o,

  output logic            valid_o,
  output logic [OutW-1:0] data_o,
  output logic [OutW-1:0] mask_o,
  input                   ready_i,

  input                   flush_i,  // If 1, send out remnant and clear state
  output logic            flush_done_o,

  // When EnProtection is set, err_o raises an error case (position variable
  // mismatch)
  output logic            err_o
);

  localparam int unsigned Width    = InW + OutW;  // storage width
  localparam int unsigned ConcatW  = Width + InW; // Input concatenated width
  localparam int unsigned PtrW     = $clog2(ConcatW+1);
  localparam int unsigned IdxW     = prim_util_pkg::vbits(InW);
  localparam int unsigned OnesCntW = $clog2(InW+1);

  logic valid_next, ready_next;
  logic [Width-1:0]   stored_data, stored_mask;
  logic [ConcatW-1:0] concat_data, concat_mask;
  logic [ConcatW-1:0] shiftl_data, shiftl_mask;
  logic [InW-1:0]     shiftr_data, shiftr_mask;

  logic [PtrW-1:0]     pos_q;         // Current write position
  logic [IdxW-1:0]     lod_idx;       // result of Leading One Detector
  logic [OnesCntW-1:0] inmask_ones;   // Counting Ones for mask_i

  logic ack_in, ack_out;

  logic flush_valid; // flush data out request
  logic flush_done;

  // Computing next position ==================================================
  always_comb begin
    // counting mask_i ones
    inmask_ones = '0;
    for (int i = 0 ; i < InW ; i++) begin
      inmask_ones = inmask_ones + OnesCntW'(mask_i[i]);
    end
  end

  logic [PtrW-1:0] pos_with_input;
  assign pos_with_input = pos_q + PtrW'(inmask_ones);

  if (EnProtection == 1'b 0) begin : g_pos_nodup
    logic [PtrW-1:0] pos_d;

    always_comb begin
      pos_d = pos_q;

      unique case ({ack_in, ack_out})
        2'b00: pos_d = pos_q;
        2'b01: pos_d = (int'(pos_q) <= OutW) ? '0 : pos_q - PtrW'(OutW);
        2'b10: pos_d = pos_with_input;
        2'b11: pos_d = (int'(pos_with_input) <= OutW) ? '0 : pos_with_input - PtrW'(OutW);
        default: pos_d = pos_q;
      endcase
    end

    always_ff @(posedge clk_i or negedge rst_ni) begin
      if (!rst_ni) begin
        pos_q <= '0;
      end else if (flush_done) begin
        pos_q <= '0;
      end else begin
        pos_q <= pos_d;
      end
    end

    assign err_o = 1'b 0; // No checker logic

  end else begin : g_pos_dupcnt // EnProtection == 1'b 1
    // incr_en: Increase the pos by cnt_step. ack_in && !ack_out
    // decr_en: Decrease the pos by cnt_step. !ack_in && ack_out
    // set_en:  Set to specific value in case of ack_in && ack_out.
    //          This case, the value could be increased or decreased based on
    //          the input size (inmask_ones)
    logic            cnt_incr_en, cnt_decr_en, cnt_set_en;
    logic [PtrW-1:0] cnt_step, cnt_set;

    assign cnt_incr_en =  ack_in && !ack_out;
    assign cnt_decr_en = !ack_in &&  ack_out;
    assign cnt_set_en  =  ack_in &&  ack_out;

    // counter has underflow protection.
    assign cnt_step = (cnt_incr_en) ? PtrW'(inmask_ones) : PtrW'(OutW);

    always_comb begin : cnt_set_logic

      // default, consuming all data
      cnt_set = '0;

      if (pos_with_input > PtrW'(OutW)) begin
        // pos_q + inmask_ones is bigger than Output width. Still data remained.
        cnt_set = pos_with_input - PtrW'(OutW);
      end
    end : cnt_set_logic


    prim_count #(
      .Width      (PtrW),
      .ResetValue ('0  )
    ) u_pos (
      .clk_i,
      .rst_ni,

      .clr_i              (flush_done),

      .set_i              (cnt_set_en),
      .set_cnt_i          (cnt_set   ),

      .incr_en_i          (cnt_incr_en),
      .decr_en_i          (cnt_decr_en),
      .step_i             (cnt_step   ),
      .commit_i           (1'b1       ),

      .cnt_o              (pos_q     ), // Current counter state
      .cnt_after_commit_o (          ), // Next counter state

      .err_o
    );
  end // g_pos_dupcnt

  //---------------------------------------------------------------------------

  // Leading one detector for mask_i
  always_comb begin
    lod_idx = 0;
    for (int i = InW-1; i >= 0 ; i--) begin
      if (mask_i[i] == 1'b1) begin
        lod_idx = IdxW'(unsigned'(i));
      end
    end
  end

  assign ack_in  = valid_i & ready_o;
  assign ack_out = valid_o & ready_i;

  // Data process =============================================================
  //  shiftr : Input data shifted right to put the leading one at bit zero
  assign shiftr_data = (valid_i) ? data_i >> lod_idx : '0;
  assign shiftr_mask = (valid_i) ? mask_i >> lod_idx : '0;

  //  shiftl : Input data shifted into the current stored position
  assign shiftl_data = ConcatW'(shiftr_data) << pos_q;
  assign shiftl_mask = ConcatW'(shiftr_mask) << pos_q;

  // concat : Merging stored and shiftl
  assign concat_data = {{(InW){1'b0}}, stored_data & stored_mask} |
                       (shiftl_data & shiftl_mask);
  assign concat_mask = {{(InW){1'b0}}, stored_mask} | shiftl_mask;

  logic [Width-1:0] stored_data_next, stored_mask_next;

  always_comb begin
    unique case ({ack_in, ack_out})
      2'b 00: begin
        stored_data_next = stored_data;
        stored_mask_next = stored_mask;
      end
      2'b 01: begin
        // ack_out : shift the amount of OutW
        stored_data_next = {{OutW{1'b0}}, stored_data[Width-1:OutW]};
        stored_mask_next = {{OutW{1'b0}}, stored_mask[Width-1:OutW]};
      end
      2'b 10: begin
        // ack_in : Store concat data
        stored_data_next = concat_data[0+:Width];
        stored_mask_next = concat_mask[0+:Width];
      end
      2'b 11: begin
        // both : shift the concat_data
        stored_data_next = concat_data[ConcatW-1:OutW];
        stored_mask_next = concat_mask[ConcatW-1:OutW];
      end
      default: begin
        stored_data_next = stored_data;
        stored_mask_next = stored_mask;
      end
    endcase
  end

  // Store the data temporary if it doesn't exceed OutW
  always_ff @(posedge clk_i or negedge rst_ni) begin
    if (!rst_ni) begin
      stored_data <= '0;
      stored_mask <= '0;
    end else if (flush_done) begin
      stored_data <= '0;
      stored_mask <= '0;
    end else begin
      stored_data <= stored_data_next;
      stored_mask <= stored_mask_next;
    end
  end
  //---------------------------------------------------------------------------

  // flush handling
  typedef enum logic {
    FlushIdle,
    FlushSend
  } flush_st_e;
  flush_st_e flush_st, flush_st_next;

  always_ff @(posedge clk_i or negedge rst_ni) begin
    if (!rst_ni) begin
      flush_st <= FlushIdle;
    end else begin
      flush_st <= flush_st_next;
    end
  end

  always_comb begin
    flush_st_next = FlushIdle;

    flush_valid = 1'b0;
    flush_done  = 1'b0;

    unique case (flush_st)
      FlushIdle: begin
        if (flush_i) begin
          flush_st_next = FlushSend;
        end else begin
          flush_st_next = FlushIdle;
        end
      end

      FlushSend: begin
        if (pos_q == '0) begin
          flush_st_next = FlushIdle;

          flush_valid = 1'b 0;
          flush_done  = 1'b 1;
        end else begin
          flush_st_next = FlushSend;

          flush_valid = 1'b 1;
          flush_done  = 1'b 0;
        end
      end
      default: begin
        flush_st_next = FlushIdle;

        flush_valid = 1'b 0;
        flush_done  = 1'b 0;
      end
    endcase
  end

  assign flush_done_o = flush_done;


  // Output signals ===========================================================
  assign valid_next = (int'(pos_q) >= OutW) ? 1'b 1 : flush_valid;

  // storage space is InW + OutW. So technically, ready_o can be asserted even
  // if `pos_q` is greater than OutW. But in order to do that, the logic should
  // use `inmask_ones` value whether pos_q+inmask_ones is less than (InW+OutW)
  // with `valid_i`. It creates a path from `valid_i` --> `ready_o`.
  // It may create a timing loop in some modules that use `ready_o` to
  // `valid_i` (which is not a good practice though)
  assign ready_next = int'(pos_q) <= OutW;

  // Output request
  assign valid_o = valid_next;
  assign data_o  = stored_data[OutW-1:0];
  assign mask_o  = stored_mask[OutW-1:0];

  // ready_o
  assign ready_o = ready_next;
  //---------------------------------------------------------------------------

  //////////////////////////////////////////////
  // Assertions, Assumptions, and Coverpoints //
  //////////////////////////////////////////////
  // Assumption: mask_i should be contiguous ones
  // e.g: 0011100 --> OK
  //      0100011 --> Not OK
  if (InW > 1) begin : gen_mask_assert
    `ASSUME(ContiguousOnesMask_M,
            valid_i |-> $countones(mask_i ^ {mask_i[InW-2:0],1'b0}) <= 2)
  end

  // Flush and Write Enable cannot be asserted same time
  `ASSUME(ExFlushValid_M, flush_i |-> !valid_i)

  // While in flush state, new request shouldn't come
  `ASSUME(ValidIDeassertedOnFlush_M,
          flush_st == FlushSend |-> $stable(valid_i))

  // If not acked, input port keeps asserting valid and data
  `ASSUME(DataIStable_M,
          ##1 valid_i && $past(valid_i) && !$past(ready_o)
          |-> $stable(data_i) && $stable(mask_i))

  `ASSERT(FlushFollowedByDone_A,
          ##1 $rose(flush_i) && !flush_done_o |-> !flush_done_o [*0:$] ##1 flush_done_o)

  // If not acked, valid_o should keep asserting
  `ASSERT(ValidOPairedWidthReadyI_A,
          valid_o && !ready_i |=> valid_o)

  // If stored data is greater than the output width, valid should be asserted
  `ASSERT(ValidOAssertedForStoredDataGTEOutW_A,
          ($countones(stored_mask) >= OutW) |-> valid_o)

  // If output port doesn't accept the data, the data should be stable
  `ASSERT(DataOStableWhenPending_A,
          ##1 valid_o && $past(valid_o)
          && !$past(ready_i) |-> $stable(data_o))

  // If input data & stored data are greater than OutW, remained should be stored
  `ASSERT(ExcessiveDataStored_A,
          ack_in && ack_out && (($countones(mask_i) + $countones(stored_mask)) > OutW)
          |=> (($past(data_i) &  $past(mask_i)) >>
               ($past(lod_idx)+OutW-$countones($past(stored_mask))))
               == stored_data)

  `ASSERT(ExcessiveMaskStored_A,
          ack_in && ack_out && (($countones(mask_i) + $countones(stored_mask)) > OutW)
          |=> ($past(mask_i) >>
               ($past(lod_idx)+OutW-$countones($past(stored_mask))))
              == stored_mask)

  // Assertions for byte hint enabled
  if (HintByteData != 0) begin : g_byte_assert
    `ASSERT_INIT(InputDividedBy8_A,  InW  % 8 == 0)
    `ASSERT_INIT(OutputDividedBy8_A, OutW % 8 == 0)

    // Masking[8*i+:8] should be all zero or all one
    for (genvar i = 0 ; i < InW/8 ; i++) begin : g_byte_input_masking
      `ASSERT(InputMaskContiguous_A,
              valid_i |-> (|mask_i[8*i+:8] == 1'b 0)
                       || (&mask_i[8*i+:8] == 1'b 1))
    end
    for (genvar i = 0 ; i < OutW/8 ; i++) begin : g_byte_output_masking
      `ASSERT(OutputMaskContiguous_A,
              valid_o |-> (|mask_o[8*i+:8] == 1'b 0)
                       || (&mask_o[8*i+:8] == 1'b 1))
    end
  end
endmodule

module prim_secded_inv_hamming_39_32_dec (
  input        [38:0] data_i,
  output logic [31:0] data_o,
  output logic [6:0] syndrome_o,
  output logic [1:0] err_o
);

  always_comb begin : p_encode
    // Syndrome calculation
    syndrome_o[0] = ^((data_i ^ 39'h2A00000000) & 39'h0156AAAD5B);
    syndrome_o[1] = ^((data_i ^ 39'h2A00000000) & 39'h029B33366D);
    syndrome_o[2] = ^((data_i ^ 39'h2A00000000) & 39'h04E3C3C78E);
    syndrome_o[3] = ^((data_i ^ 39'h2A00000000) & 39'h0803FC07F0);
    syndrome_o[4] = ^((data_i ^ 39'h2A00000000) & 39'h1003FFF800);
    syndrome_o[5] = ^((data_i ^ 39'h2A00000000) & 39'h20FC000000);
    syndrome_o[6] = ^((data_i ^ 39'h2A00000000) & 39'h7FFFFFFFFF);

    // Corrected output calculation
    data_o[0] = (syndrome_o == 7'h43) ^ data_i[0];
    data_o[1] = (syndrome_o == 7'h45) ^ data_i[1];
    data_o[2] = (syndrome_o == 7'h46) ^ data_i[2];
    data_o[3] = (syndrome_o == 7'h47) ^ data_i[3];
    data_o[4] = (syndrome_o == 7'h49) ^ data_i[4];
    data_o[5] = (syndrome_o == 7'h4a) ^ data_i[5];
    data_o[6] = (syndrome_o == 7'h4b) ^ data_i[6];
    data_o[7] = (syndrome_o == 7'h4c) ^ data_i[7];
    data_o[8] = (syndrome_o == 7'h4d) ^ data_i[8];
    data_o[9] = (syndrome_o == 7'h4e) ^ data_i[9];
    data_o[10] = (syndrome_o == 7'h4f) ^ data_i[10];
    data_o[11] = (syndrome_o == 7'h51) ^ data_i[11];
    data_o[12] = (syndrome_o == 7'h52) ^ data_i[12];
    data_o[13] = (syndrome_o == 7'h53) ^ data_i[13];
    data_o[14] = (syndrome_o == 7'h54) ^ data_i[14];
    data_o[15] = (syndrome_o == 7'h55) ^ data_i[15];
    data_o[16] = (syndrome_o == 7'h56) ^ data_i[16];
    data_o[17] = (syndrome_o == 7'h57) ^ data_i[17];
    data_o[18] = (syndrome_o == 7'h58) ^ data_i[18];
    data_o[19] = (syndrome_o == 7'h59) ^ data_i[19];
    data_o[20] = (syndrome_o == 7'h5a) ^ data_i[20];
    data_o[21] = (syndrome_o == 7'h5b) ^ data_i[21];
    data_o[22] = (syndrome_o == 7'h5c) ^ data_i[22];
    data_o[23] = (syndrome_o == 7'h5d) ^ data_i[23];
    data_o[24] = (syndrome_o == 7'h5e) ^ data_i[24];
    data_o[25] = (syndrome_o == 7'h5f) ^ data_i[25];
    data_o[26] = (syndrome_o == 7'h61) ^ data_i[26];
    data_o[27] = (syndrome_o == 7'h62) ^ data_i[27];
    data_o[28] = (syndrome_o == 7'h63) ^ data_i[28];
    data_o[29] = (syndrome_o == 7'h64) ^ data_i[29];
    data_o[30] = (syndrome_o == 7'h65) ^ data_i[30];
    data_o[31] = (syndrome_o == 7'h66) ^ data_i[31];

    // err_o calc. bit0: single error, bit1: double error
    err_o[0] = syndrome_o[6];
    err_o[1] = |syndrome_o[5:0] & ~syndrome_o[6];
  end
endmodule

module prim_onehot_mux #(
  parameter int Width  = 32,
  parameter int Inputs = 8
) (
  // Clock and reset only for assertions
  input clk_i,
  input rst_ni,

  input  logic [Width-1:0]  in_i [Inputs],
  input  logic [Inputs-1:0] sel_i, // Must be one-hot or zero
  output logic [Width-1:0]  out_o
);
  logic [Inputs-1:0] in_mux [Width];

  for (genvar b = 0; b < Width; ++b) begin : g_in_mux_outer
    logic [Inputs-1:0] out_mux_bits;

    for (genvar i = 0; i < Inputs; ++i) begin : g_in_mux_inner
      assign in_mux[b][i] = in_i[i][b];
    end

    prim_and2 #(.Width(Inputs)) u_mux_bit_and(
      .in0_i(in_mux[b]),
      .in1_i(sel_i),
      .out_o(out_mux_bits)
    );

    assign out_o[b] = |out_mux_bits;
  end

  logic unused_clk;
  logic unused_rst_n;

  // clock and reset only needed for assertion
  assign unused_clk   = clk_i;
  assign unused_rst_n = rst_ni;

  `ASSERT(SelIsOnehot_A, $onehot0(sel_i))
endmodule

module prim_fifo_sync #(
  parameter int unsigned Width       = 16,
  parameter bit Pass                 = 1'b1, // if == 1 allow requests to pass through empty FIFO
  parameter int unsigned Depth       = 4,
  parameter bit OutputZeroIfEmpty    = 1'b1, // if == 1 always output 0 when FIFO is empty
  parameter bit NeverClears          = 1'b0, // if set, the clr_i port is never high
  parameter bit Secure               = 1'b0, // use prim count for pointers
  // derived parameter
  localparam int          DepthW     = prim_util_pkg::vbits(Depth+1)
) (
  input                   clk_i,
  input                   rst_ni,
  // synchronous clear / flush port
  input                   clr_i,
  // write port
  input                   wvalid_i,
  output                  wready_o,
  input   [Width-1:0]     wdata_i,
  // read port
  output                  rvalid_o,
  input                   rready_i,
  output  [Width-1:0]     rdata_o,
  // occupancy
  output                  full_o,
  output  [DepthW-1:0]    depth_o,
  output                  err_o
);


  // FIFO is in complete passthrough mode
  if (Depth == 0) begin : gen_passthru_fifo
    `ASSERT_INIT(paramCheckPass, Pass == 1)

    assign depth_o = 1'b0; //output is meaningless

    // device facing
    assign rvalid_o = wvalid_i;
    assign rdata_o = wdata_i;

    // host facing
    assign wready_o = rready_i;
    assign full_o = 1'b1;

    // this avoids lint warnings
    logic unused_clr;
    assign unused_clr = clr_i;

    // No error
    assign err_o = 1'b 0;

  // FIFO has space for a single element (and doesn't need proper counters)
  end else if (Depth == 1) begin : gen_singleton_fifo

    // full_q is true if the (singleton) queue has data
    logic full_d, full_q;

    assign full_o = full_q;
    assign depth_o = full_q;
    assign wready_o = ~full_q;

    // We can always read from the storage if it contains something, so rvalid_o is true if full_q
    // is true. Enabling pass-through mode also allows data to flow through if wvalid_i is true.
    assign rvalid_o = full_q || (Pass && wvalid_i);

    // For there to be data on the next cycle, there must either be new data coming in (so !rvalid_o
    // && wvalid_i) or we must be keeping the current data (so rvalid_o && !rready_i). Using
    // rvalid_o instead of full_q ensures we get the right behaviour with pass-through.
    //
    // In either case, any stored data will be forgotten if clr_i is true.
    assign full_d = (rvalid_o ? !rready_i : wvalid_i) && !clr_i;

    always_ff @(posedge clk_i or negedge rst_ni) begin
      if (!rst_ni) begin
        full_q <= 1'b0;
      end else begin
        full_q <= full_d;
      end
    end

    logic [Width-1:0] storage;
    always_ff @(posedge clk_i) begin
      if (wvalid_i && wready_o) storage <= wdata_i;
    end

    logic [Width-1:0] rdata_int;
    assign rdata_int = (full_q || Pass == 1'b0) ? storage : wdata_i;

    assign rdata_o = (OutputZeroIfEmpty && !rvalid_o) ? Width'(0) : rdata_int;

    // The larger FIFO implementation uses prim_count for read and write pointers. If Secure is
    // true, prim_count duplicates and checks these pointers to guard against fault injection. We do
    // something similar here, duplicating and checking a "1 bit counter".
    //
    // The duplication is inverted, which means we expect full_q ^ inv_full to be true and generate
    // an error signal if it is not. This error signal gets registered to avoid potential CDC issues
    // downstream.
    if (!Secure) begin : gen_not_secure
      assign err_o = 1'b0;
    end else begin : gen_secure
      logic inv_full;

      prim_flop #(
        .Width(1),
        .ResetValue(1'b1)
      ) u_inv_full (
        .clk_i,
        .rst_ni,
        .d_i (~full_d),
        .q_o (inv_full)
      );

      logic err_d, err_q;
      assign err_d = ~(full_q ^ inv_full);

      always_ff @(posedge clk_i or negedge rst_ni) begin
        if (!rst_ni) begin
          err_q <= 1'b0;
        end else begin
          err_q <= err_d;
        end
      end

      assign err_o = err_q;
    end

  // Normal FIFO construction
  end else begin : gen_normal_fifo

    localparam int unsigned PtrW = prim_util_pkg::vbits(Depth);

    logic [PtrW-1:0] fifo_wptr, fifo_rptr;
    logic            fifo_incr_wptr, fifo_incr_rptr, fifo_empty;

    // module under reset flag
    logic under_rst;
    always_ff @(posedge clk_i or negedge rst_ni) begin
      if (!rst_ni) begin
        under_rst <= 1'b1;
      end else if (under_rst) begin
        under_rst <= ~under_rst;
      end
    end

    logic empty;

    // full and not ready for write are two different concepts.
    // The latter can be '0' when under reset, while the former is an indication that no more
    // entries can be written.
    assign wready_o = ~full_o & ~under_rst;

    prim_fifo_sync_cnt #(
      .Depth(Depth),
      .Secure(Secure),
      .NeverClears(NeverClears)
    ) u_fifo_cnt (
      .clk_i,
      .rst_ni,
      .clr_i,
      .incr_wptr_i(fifo_incr_wptr),
      .incr_rptr_i(fifo_incr_rptr),
      .wptr_o(fifo_wptr),
      .rptr_o(fifo_rptr),
      .full_o,
      .empty_o(fifo_empty),
      .depth_o,
      .err_o
    );
    assign fifo_incr_wptr = wvalid_i & wready_o;
    assign fifo_incr_rptr = rvalid_o & rready_i & ~under_rst;

    logic [Depth-1:0][Width-1:0] storage;
    logic [Width-1:0] storage_rdata;

    assign storage_rdata = storage[fifo_rptr];

    always_ff @(posedge clk_i)
      if (fifo_incr_wptr) begin
        storage[fifo_wptr] <= wdata_i;
      end

    logic [Width-1:0] rdata_int;
    if (Pass == 1'b1) begin : gen_pass
      assign rdata_int = (fifo_empty && wvalid_i) ? wdata_i : storage_rdata;
      assign empty = fifo_empty & ~wvalid_i;
      assign rvalid_o = ~empty & ~under_rst;
    end else begin : gen_nopass
      assign rdata_int = storage_rdata;
      assign empty = fifo_empty;
      assign rvalid_o = ~empty;
    end

    if (OutputZeroIfEmpty == 1'b1) begin : gen_output_zero
      assign rdata_o = empty ? Width'(0) : rdata_int;
    end else begin : gen_no_output_zero
      assign rdata_o = rdata_int;
    end

    `ASSERT(depthShallNotExceedParamDepth, !empty |-> depth_o <= DepthW'(Depth))
    `ASSERT(OnlyRvalidWhenNotUnderRst_A, rvalid_o -> ~under_rst)
  end // block: gen_normal_fifo


  if (NeverClears) begin : gen_never_clears
    `ASSERT(NeverClears_A, !clr_i)
  end

  //////////////////////
  // Known Assertions //
  //////////////////////

  `ASSERT_KNOWN_IF(DataKnown_A, rdata_o, rvalid_o)
  `ASSERT_KNOWN(DepthKnown_A, depth_o)
  `ASSERT_KNOWN(RvalidKnown_A, rvalid_o)
  `ASSERT_KNOWN(WreadyKnown_A, wready_o)

`ifdef INC_ASSERT
  // When Depth=1 and Secure=1, there is a specialized countermeasure that works by replicating
  // the full_q flag. To set the logic value below to one, the user must use the
  // ASSERT_PRIM_FIFO_SYNC_SINGLETON_ERROR_TRIGGER_ALERT macro (which checks that the error signal
  // causes an alert).
  //
  // If the user hasn't done so, unused_assert_connected will be zero and ASSERT_INIT_NET will
  // fail.
  logic unused_assert_connected;
  if (Depth == 1 && Secure) begin : gen_secure_singleton
    `ASSERT_INIT_NET(AssertConnected_A, unused_assert_connected === 1'b1)
  end
`endif
endmodule

module prim_ascon_sbox (
  output logic [4:0] state_o,
  input  logic [4:0] state_i
);

  logic [4:0] temp_w [4];

  assign temp_w[0] = state_i;
  assign temp_w[1] = {temp_w[0][3] ^ temp_w[0][4],
                      temp_w[0][3],
                      temp_w[0][1] ^ temp_w[0][2],
                      temp_w[0][1],
                      temp_w[0][0] ^ temp_w[0][4]
                      };
  assign temp_w[2] = {temp_w[1][4] ^ ((~temp_w[1][0]) & temp_w[1][1]),
                      temp_w[1][3] ^ ((~temp_w[1][4]) & temp_w[1][0]),
                      temp_w[1][2] ^ ((~temp_w[1][3]) & temp_w[1][4]),
                      temp_w[1][1] ^ ((~temp_w[1][2]) & temp_w[1][3]),
                      temp_w[1][0] ^ ((~temp_w[1][1]) & temp_w[1][2])
                      };
  assign temp_w[3] = {temp_w[2][4],
                      temp_w[2][3] ^ temp_w[2][2],
                      ~temp_w[2][2],
                      temp_w[2][1] ^ temp_w[2][0],
                      temp_w[2][0] ^ temp_w[2][4]
                      };
  assign state_o = temp_w[3];

endmodule

module prim_ram_1p_adv import prim_ram_1p_pkg::*; #(
  parameter  int Depth                = 512,
  // Setting InstDepth to a smaller value than Depth enables RAM tiling. RAM is tiled to
  // ceil(Depth/InstDepth) prim_ram_1p instances, each InstDepth deep.
  parameter  int InstDepth            = Depth,
  parameter  int Width                = 32,
  parameter  int DataBitsPerMask      = 1,  // Number of data bits per bit of write mask
  parameter      MemInitFile          = "", // VMEM file to initialize the memory with

  // Configurations
  parameter  bit EnableECC            = 0, // Enables per-word ECC
  parameter  bit EnableParity         = 0, // Enables per-Byte Parity
  parameter  bit EnableInputPipeline  = 0, // Adds an input register (read latency +1)
  parameter  bit EnableOutputPipeline = 0, // Adds an output register (read latency +1)

  // This switch allows to switch to standard Hamming ECC instead of the HSIAO ECC.
  // It is recommended to leave this parameter at its default setting (HSIAO),
  // since this results in a more compact and faster implementation.
  parameter bit HammingECC            = 0,

  localparam int Aw                   = prim_util_pkg::vbits(Depth),
  // Compute RAM tiling
  localparam int NumRamInst           = prim_util_pkg::ceil_div(Depth, InstDepth),
  localparam int InstAw               = prim_util_pkg::vbits(InstDepth)
) (
  input clk_i,
  input rst_ni,

  input                               req_i,
  input                               write_i,
  input        [Aw-1:0]               addr_i,
  input        [Width-1:0]            wdata_i,
  input        [Width-1:0]            wmask_i,
  output logic [Width-1:0]            rdata_o,
  output logic                        rvalid_o, // read response (rdata_o) is valid
  output logic [1:0]                  rerror_o, // Bit1: Uncorrectable, Bit0: Correctable

  // config
  input  ram_1p_cfg_t     [NumRamInst-1:0] cfg_i,
  output ram_1p_cfg_rsp_t [NumRamInst-1:0] cfg_rsp_o,

  // When detecting multi-bit encoding errors, raise alert.
  output logic                             alert_o
);

  import prim_mubi_pkg::mubi4_t;
  import prim_mubi_pkg::mubi4_and_hi;
  import prim_mubi_pkg::mubi4_bool_to_mubi;
  import prim_mubi_pkg::mubi4_test_invalid;
  import prim_mubi_pkg::mubi4_test_true_loose;
  import prim_mubi_pkg::mubi4_test_true_strict;
  import prim_mubi_pkg::MuBi4True;
  import prim_mubi_pkg::MuBi4False;
  import prim_mubi_pkg::MuBi4Width;

  `ASSERT_INIT(CannotHaveEccAndParity_A, !(EnableParity && EnableECC))

  // Calculate ECC width
  localparam int ParWidth  = (EnableParity) ? Width/8 :
                             (!EnableECC)   ? 0 :
                             (Width <=   4) ? 4 :
                             (Width <=  11) ? 5 :
                             (Width <=  26) ? 6 :
                             (Width <=  57) ? 7 :
                             (Width <= 120) ? 8 : 8 ;
  localparam int TotalWidth = Width + ParWidth;

  // If byte parity is enabled, the write enable bits are used to write memory columns
  // with 8 + 1 = 9 bit width (data plus corresponding parity bit).
  // If ECC is enabled, the DataBitsPerMask is ignored.
  localparam int LocalDataBitsPerMask = (EnableParity) ? 9          :
                                        (EnableECC)    ? TotalWidth :
                                                         DataBitsPerMask;

  ////////////////////////////
  // RAM Primitive Instance //
  ////////////////////////////

  mubi4_t                  req_q,     req_d,    req_buf_d ;
  logic [MuBi4Width-1:0]   req_buf_b_d;
  logic                    req_q_b ;
  mubi4_t                  write_q,   write_d,  write_buf_d ;
  logic [MuBi4Width-1:0]   write_buf_b_d;
  logic                    write_q_b ;
  logic [Aw-1:0]           addr_q,    addr_d ;
  logic [TotalWidth-1:0]   wdata_q,   wdata_d ;
  logic [TotalWidth-1:0]   wmask_q,   wmask_d ;
  mubi4_t                  rvalid_q,  rvalid_d, rvalid_sram_q, rvalid_sram_d ;
  logic [Width-1:0]        rdata_q,   rdata_d ;
  logic [TotalWidth-1:0]   rdata_sram ;
  logic [1:0]              rerror_q,  rerror_d ;

  assign req_q_b = mubi4_test_true_loose(req_q);
  assign write_q_b = mubi4_test_true_loose(write_q);

  logic [NumRamInst-1:0] inst_req_d, inst_req_q, rvalid_inst;
  logic [InstAw-1:0] inst_addr;
  logic [NumRamInst-1:0] [Width-1:0] inst_rdata;

  // The lower InstAw bits of the address are used to address within one RAM primitive
  assign inst_addr = addr_q[InstAw-1:0];

  // The upper bits Aw-1:InstAw of the address select which RAM instance is selected. A special case
  // is needed when no tiling is performed and only a single RAM macro is instantiated. Here, we
  // can directly use the request signal and no demuxing is needed.
  if (NumRamInst == 1) begin : gen_single_inst_req
    assign inst_req_d[0] = req_q_b;
  end else begin : gen_multi_inst_req
    always_comb begin
      inst_req_d = '0;

      for (int i = 0; i < NumRamInst; i++) begin
        if (req_q_b && (i == addr_q[Aw-1:InstAw])) begin
          inst_req_d[i] = 1'b1;
        end
      end
    end
  end

  // Flop the instance request signal to know to know which
  // tile to select for read data on the next cycle
  always_ff @(posedge clk_i or negedge rst_ni) begin
    if (!rst_ni) begin
      inst_req_q <= '0;
    end else begin
      inst_req_q <= inst_req_d;
    end
  end

  // Ensure that only one RAM instance gets activated
  `ASSERT(OneHotInstReq_A, $onehot0(inst_req_d))

  for (genvar i = 0; i < NumRamInst; i++) begin : gen_ram_inst
    prim_ram_1p #(
      .MemInitFile     (MemInitFile),

      .Width           (TotalWidth),
      .Depth           (InstDepth),
      .DataBitsPerMask (LocalDataBitsPerMask)
    ) u_mem (
      .clk_i,
      .rst_ni,

      .req_i     (inst_req_d[i]),
      .write_i   (write_q_b),
      .addr_i    (inst_addr),
      .wdata_i   (wdata_q),
      .wmask_i   (wmask_q),
      .rdata_o   (inst_rdata[i]),
      .cfg_i     (cfg_i[i]),
      .cfg_rsp_o (cfg_rsp_o[i])
    );
  end

  // Mux output data
  always_comb begin
    rdata_sram = '0;

    for (int i = 0; i < NumRamInst; i++) begin
      // Determine which RAM tile we accessed based on the floped inst_req signal and we really
      // got an rvalid. This determines if we mux the output data of that particular RAM tile.
      rvalid_inst[i] = mubi4_test_true_strict(
        mubi4_and_hi(mubi4_bool_to_mubi(inst_req_q[i]), rvalid_sram_q));

      if(rvalid_inst[i]) begin
        rdata_sram = inst_rdata[i];
      end
    end
  end

  assign rvalid_sram_d = mubi4_and_hi(req_q, mubi4_t'(~write_q));

  always_ff @(posedge clk_i or negedge rst_ni) begin
    if (!rst_ni) begin
      rvalid_sram_q <= MuBi4False;
    end else begin
      rvalid_sram_q <= rvalid_sram_d;
    end
  end

  assign req_d              = mubi4_bool_to_mubi(req_i);
  assign write_d            = mubi4_bool_to_mubi(write_i);
  assign addr_d             = addr_i;
  assign rvalid_o           = mubi4_test_true_loose(rvalid_q);
  assign rdata_o            = rdata_q;
  assign rerror_o           = rerror_q;

  prim_buf #(
    .Width(MuBi4Width)
  ) u_req_d_buf (
    .in_i (req_d),
    .out_o(req_buf_b_d)
  );

  assign req_buf_d = mubi4_t'(req_buf_b_d);

  prim_buf #(
    .Width(MuBi4Width)
  ) u_write_d_buf (
    .in_i (write_d),
    .out_o(write_buf_b_d)
  );

  assign write_buf_d = mubi4_t'(write_buf_b_d);

  /////////////////////////////
  // ECC / Parity Generation //
  /////////////////////////////

  if (EnableParity == 0 && EnableECC) begin : gen_secded
    logic unused_wmask;
    assign unused_wmask = ^wmask_i;

    // check supported widths
    `ASSERT_INIT(SecDecWidth_A, Width inside {16, 32})

    // the wmask is constantly set to 1 in this case
    `ASSERT(OnlyWordWritePossibleWithEccPortA_A, req_i |->
          wmask_i == {Width{1'b1}})

    assign wmask_d = {TotalWidth{1'b1}};

    if (Width == 16) begin : gen_secded_22_16
      if (HammingECC) begin : gen_hamming
        prim_secded_inv_hamming_22_16_enc u_enc (
          .data_i(wdata_i),
          .data_o(wdata_d)
        );
        prim_secded_inv_hamming_22_16_dec u_dec (
          .data_i     (rdata_sram),
          .data_o     (rdata_d[0+:Width]),
          .syndrome_o ( ),
          .err_o      (rerror_d)
        );
      end else begin : gen_hsiao
        prim_secded_inv_22_16_enc u_enc (
          .data_i(wdata_i),
          .data_o(wdata_d)
        );
        prim_secded_inv_22_16_dec u_dec (
          .data_i     (rdata_sram),
          .data_o     (rdata_d[0+:Width]),
          .syndrome_o ( ),
          .err_o      (rerror_d)
        );
      end
    end else if (Width == 32) begin : gen_secded_39_32
      if (HammingECC) begin : gen_hamming
        prim_secded_inv_hamming_39_32_enc u_enc (
          .data_i(wdata_i),
          .data_o(wdata_d)
        );
        prim_secded_inv_hamming_39_32_dec u_dec (
          .data_i     (rdata_sram),
          .data_o     (rdata_d[0+:Width]),
          .syndrome_o ( ),
          .err_o      (rerror_d)
        );
      end else begin : gen_hsiao
        prim_secded_inv_39_32_enc u_enc (
          .data_i(wdata_i),
          .data_o(wdata_d)
        );
        prim_secded_inv_39_32_dec u_dec (
          .data_i     (rdata_sram),
          .data_o     (rdata_d[0+:Width]),
          .syndrome_o ( ),
          .err_o      (rerror_d)
        );
      end
    end

  end else if (EnableParity) begin : gen_byte_parity

    `ASSERT_INIT(WidthNeedsToBeByteAligned_A, Width % 8 == 0)
    `ASSERT_INIT(ParityNeedsByteWriteMask_A, DataBitsPerMask == 8)

    always_comb begin : p_parity
      rerror_d = '0;
      for (int i = 0; i < Width/8; i ++) begin
        // Data mapping. We have to make 8+1 = 9 bit groups
        // that have the same write enable such that FPGA tools
        // can map this correctly to BRAM resources.
        wmask_d[i*9 +: 8] = wmask_i[i*8 +: 8];
        wdata_d[i*9 +: 8] = wdata_i[i*8 +: 8];
        rdata_d[i*8 +: 8] = rdata_sram[i*9 +: 8];

        // parity generation (odd parity)
        wdata_d[i*9 + 8] = ~(^wdata_i[i*8 +: 8]);
        wmask_d[i*9 + 8] = &wmask_i[i*8 +: 8];
        // parity decoding (errors are always uncorrectable)
        rerror_d[1] |= ~(^{rdata_sram[i*9 +: 8], rdata_sram[i*9 + 8]});
      end
    end
  end else begin : gen_nosecded_noparity
    assign wmask_d = wmask_i;
    assign wdata_d = wdata_i;

    assign rdata_d  = rdata_sram[0+:Width];
    assign rerror_d = '0;
  end

  assign rvalid_d = rvalid_sram_q;

  /////////////////////////////////////
  // Input/Output Pipeline Registers //
  /////////////////////////////////////

  if (EnableInputPipeline) begin : gen_regslice_input
    // Put the register slices between ECC encoding to SRAM port

    // If no ECC or parity is used, do not use prim_flop to allow synthesis
    // tool to optimize the registers.
    if (EnableECC || EnableParity) begin : gen_prim_flop
      prim_flop #(
        .Width(MuBi4Width),
        .ResetValue(MuBi4Width'(MuBi4False))
      ) u_write_flop (
        .clk_i,
        .rst_ni,
        .d_i(MuBi4Width'(write_buf_d)),
        .q_o({write_q})
      );

      prim_flop #(
        .Width(MuBi4Width),
        .ResetValue(MuBi4Width'(MuBi4False))
      ) u_req_flop (
        .clk_i,
        .rst_ni,
        .d_i(MuBi4Width'(req_buf_d)),
        .q_o({req_q})
      );
    end else begin: gen_no_prim_flop
      always_ff @(posedge clk_i or negedge rst_ni) begin
        if (!rst_ni) begin
          write_q <= MuBi4False;
          req_q   <= MuBi4False;
        end else begin
          write_q <= write_buf_d;
          req_q   <= req_buf_d;
        end
      end
    end

    always_ff @(posedge clk_i or negedge rst_ni) begin
      if (!rst_ni) begin
        addr_q  <= '0;
        wdata_q <= '0;
        wmask_q <= '0;
      end else begin
        addr_q  <= addr_d;
        wdata_q <= wdata_d;
        wmask_q <= wmask_d;
      end
    end
  end else begin : gen_dirconnect_input
    assign req_q   = req_buf_d;
    assign write_q = write_buf_d;
    assign addr_q  = addr_d;
    assign wdata_q = wdata_d;
    assign wmask_q = wmask_d;
  end

  if (EnableOutputPipeline) begin : gen_regslice_output
    // Put the register slices between ECC decoding to output

    // If no ECC or parity is used, do not use prim_flop to allow synthesis
    // tool to optimize the registers.
    if (EnableECC || EnableParity) begin : gen_prim_rvalid_flop
      prim_flop #(
        .Width(MuBi4Width),
        .ResetValue(MuBi4Width'(MuBi4False))
      ) u_rvalid_flop (
        .clk_i,
        .rst_ni,
        .d_i(MuBi4Width'(rvalid_d)),
        .q_o({rvalid_q})
      );
    end else begin: gen_no_prim_rvalid_flop
      always_ff @(posedge clk_i or negedge rst_ni) begin
        if (!rst_ni) begin
          rvalid_q <= MuBi4False;
        end else begin
          rvalid_q <= rvalid_d;
        end
      end
    end

    always_ff @(posedge clk_i or negedge rst_ni) begin
      if (!rst_ni) begin
        rdata_q  <= '0;
        rerror_q <= '0;
      end else begin
        rdata_q  <= rdata_d;
        // tie to zero if the read data is not valid
        rerror_q <= rerror_d & {2{mubi4_test_true_loose(rvalid_d)}};
      end
    end
  end else begin : gen_dirconnect_output
    assign rvalid_q = rvalid_d;
    assign rdata_q  = rdata_d;
    // tie to zero if the read data is not valid
    assign rerror_q = rerror_d & {2{mubi4_test_true_loose(rvalid_d)}};
  end

  assign alert_o = mubi4_test_invalid(req_q) | mubi4_test_invalid(write_q) |
                   mubi4_test_invalid(rvalid_q) | mubi4_test_invalid(rvalid_sram_q);

endmodule

module is to have a small and simple module that can be synthesized (and its
// netlist can be inspected) for easy constraint checking.
// The synthesis tool is not allowed to perform constant propagation, merging of redundant signals,
// and performing logic optimization accross preserved cells.
//
// 1. In the synthesized netlist, the following number of size_only instances must be present:
// e.g. grep -c -R u_size_only_x netlist.v (make sure the design is uniquified)
// |-------------------------------------------------------------------|
// | Test | buf | and2 | xor | xnor | flop | clock_mux2 | clock_gating |
// | -----| ----|------|-----|------|------|------------|--------------|
// | 1    | 192 | -    |  -  | -    | -    | -          | -            |
// | 2    | -   | -    |  64 | -    | -    | -          | -            |
// | 3    |  48 | 48   |  48 | 48   | 144  | -          | -            |
// | 4    |   8 |  8   |   8 |  8   |  24  | -          | -            |
// | 5    |  36 | -    |  -  | -    |  24  | -          | -            |
// | 6    |  16 | -    |  -  | -    |   8  | -          | -            |
// | 7    | -   | -    |  -  | -    |  32  | 2          | 2            |
// | 8    |  16 | -    |  -  | -    |   8  | -          | -            |
// | 9    |  12 | -    |  -  | -    |  12  | -          | -            |
// | -----| ----|------|-----|------|------|------------|--------------|
// |total | 328 | 56   | 120 | 56   | 252  | 2          | 2            |
// |-------------------------------------------------------------------|
//
// 2. None of the test_*_o signals can be driven by a constant 0 or 1.
// The instantiated size_only instances must prevent logic optimizations and keep
// the output comparators
// e.g. check_design -constant
//
// 3. None of the buffers or flip flops can be unloaded:
// e.g. check_design -unloaded_comb -unloaded
//
// 4. lc_en_o, mubi_o signals cannot be driven to a constant value
// (optimization accross preserevd instances cannot happen)
//
// 5. lc_en_i, mubi_i signals can only be connected to variables, or legal mubi/lc values
// e.g. grep -oE '(\.lc_en_i|\.mubi_i) \([^)]+'  netlist.v

`include "prim_assert.sv"

module prim_sdc_example #(
  localparam int unsigned Width = 8, // these localparams are constant, don't override
  localparam int unsigned NumSender = 4,
  localparam int unsigned NumTests = 12,
  localparam int unsigned NumSenderLc = 2,
  localparam int unsigned NumTestsLc = 6
) (
  input logic                                    clk_i,
  input logic                                    rst_ni,

  input  logic [31:0]                            data_a_i,
  input  logic [31:0]                            data_b_i,
  input  logic [31:0]                            data_c_i,

  input  logic                                   en_i,

  output logic [31:0]                            test_res_o,
  output logic                                   test_xor_o,
  output logic                                   test_const_o,
  output logic                                   test_var_o,
  output logic [1:0]                             test_mubi_out_o,
  output logic [NumSender-1:0][NumTests-1:0]     test_mubi_bool_out_o,
  output logic [3:0][Width-1:0]                  test_clk_gen_o,
  output logic [1:0]                             test_lc_out_o,
  output logic [NumSenderLc-1:0][NumTestsLc-1:0] test_lc_bool_out_o
);

  import prim_mubi_pkg::*;

  //////////////////////////////////////////////////////
  // Test 1: basic buffers with arithmetic operations //
  //////////////////////////////////////////////////////
  // It is not allowed that arithmetic operations are merged across prim_bufs
  // The following size_only cells are expected:
  // 6*32 size_only_buf

  localparam int unsigned NumStages = 3;
  localparam int unsigned ConstA = 32'h0FF0_ABBA;

  logic [NumStages-1:0][31:0] res, res_buf;
  logic [31:0] data_a, data_b, data_c;

  prim_buf #(
    .Width(32)
  ) u_prim_buf_data_a (
    .in_i (data_a_i),
    .out_o(data_a)
  );

  prim_buf #(
    .Width(32)
  ) u_prim_buf_data_b (
    .in_i (data_b_i),
    .out_o(data_b)
  );

  prim_buf #(
    .Width(32)
  ) u_prim_buf_data_c (
    .in_i (data_c_i),
    .out_o(data_c)
  );

  assign res[0] = data_a + data_b;

  prim_buf #(
    .Width(32)
  ) u_prim_buf_res0 (
    .in_i (res[0]),
    .out_o(res_buf[0])
  );

  assign res[1] = res_buf[0] + ConstA;

  prim_buf #(
    .Width(32)
  ) u_prim_buf_res1 (
    .in_i (res[1]),
    .out_o(res_buf[1])
  );

  assign res[2] = res_buf[1] * data_c;

  prim_buf #(
    .Width(32)
  ) u_prim_buf_res2 (
    .in_i (res[2]),
    .out_o(res_buf[2])
  );

  assign test_res_o = res_buf[2];

  ////////////////////////////////////////////////////////////////
  // Test 2: two xor operations in a row result in the identity //
  ////////////////////////////////////////////////////////////////
  // This optimization is prevented by the preserved instances
  // The following size_only cells are expected:
  // 2*32 size_only_xor2
  // test_xor_o must be the result of a comparison and not tied to high

  logic [31:0] res_xor2_0, res_xor2_1;

  prim_xor2 #(
    .Width(32)
  ) u_prim_xor2_0 (
    .in0_i(data_a_i),
    .in1_i(data_b_i),
    .out_o(res_xor2_0)
  );

  prim_xor2 #(
    .Width(32)
  ) u_prim_xor2_1 (
    .in0_i(res_xor2_0),
    .in1_i(data_b_i),
    .out_o(res_xor2_1)
  );

  // The comparison below is always true because
  // res_xor2_1 = res_xor2_0 ^ data_b_i = data_a_i ^ data_b_i ^ data_b_i = data_a_i
  // But the comparison cannot be optimized because logic propagation is not allowed
  // across preserved instances
  assign test_xor_o = (res_xor2_1 == data_a_i) ? 1'b1 : 1'b0;

  //////////////////////////////////////////////////////////
  // Test 3: prim basic gates tests with constant inputs: //
  //////////////////////////////////////////////////////////
  // These gates cannot be removed
  // The following size_only cells are expected:
  // 6*8 size_only_buf
  // 6*8 size_only_and2
  // 6*8 size_only_xor
  // 6*8 size_only_xnor
  // 6*8*3 size_only_flop

  localparam int unsigned NumConst = 6;
  localparam int unsigned NumGates = 7;

  localparam logic [Width-1:0] ConstIn0 [NumConst] = {8'hAB,
                                                      8'hBA,
                                                      8'h01,
                                                      8'hFE,
                                                      8'hF0,
                                                      8'h0F};

  localparam logic [Width-1:0] ConstIn1 [NumConst] = {8'h10,
                                                      8'h25,
                                                      8'h39,
                                                      8'hBC,
                                                      8'hD1,
                                                      8'h5F};

  logic [NumConst-1:0][NumGates-1:0][Width-1:0] const_out_not_removed;

  for (genvar idx = 0; idx < NumConst; idx++) begin : g_num_consts
    prim_buf #(
      .Width(Width)
    ) u_prim_buf (
      .in_i (ConstIn0[idx]),
      .out_o(const_out_not_removed[idx][0])
    );

    prim_and2 #(
      .Width(Width)
    ) u_prim_and2 (
      .in0_i(ConstIn0[idx]),
      .in1_i(ConstIn1[idx]),
      .out_o(const_out_not_removed[idx][1])
    );

    prim_xor2 #(
      .Width(Width)
    ) u_prim_xor2 (
      .in0_i(ConstIn0[idx]),
      .in1_i(ConstIn1[idx]),
      .out_o(const_out_not_removed[idx][2])
    );

    prim_xnor2 #(
      .Width(Width)
    ) u_prim_xnor2 (
      .in0_i(ConstIn0[idx]),
      .in1_i(ConstIn1[idx]),
      .out_o(const_out_not_removed[idx][3])
    );

    prim_flop #(
     .Width(Width)
    ) u_prim_flop (
      .clk_i (clk_i),
      .rst_ni(rst_ni),
      .d_i   (ConstIn0[idx]),
      .q_o   (const_out_not_removed[idx][4])
    );

    prim_flop_en #(
     .Width(Width)
    ) u_prim_flop_en (
      .clk_i (clk_i),
      .rst_ni(rst_ni),
      .en_i  (en_i),
      .d_i   (ConstIn0[idx]),
      .q_o   (const_out_not_removed[idx][5])
    );

    prim_flop_no_rst #(
     .Width(Width)
    ) u_prim_flop_no_rst (
      .clk_i(clk_i),
      .d_i  (ConstIn0[idx]),
      .q_o  (const_out_not_removed[idx][6])
    );
  end

  assign test_const_o = ^const_out_not_removed;

  ///////////////////////////////////////////////////
  // Test 4: prim basic gates with variable inputs //
  ///////////////////////////////////////////////////
  // The following size_only cells are expected:
  // 8 size_only_buf
  // 8 size_only_and2
  // 8 size_only_xor
  // 8 size_only_xnor
  // 8*3 size_only_flop

  logic [NumGates-1:0][Width-1:0] var_out_not_removed;

  prim_buf #(
      .Width(Width)
  ) u_prim_buf (
      .in_i (data_a[Width-1:0]),
      .out_o(var_out_not_removed[0])
  );
  prim_and2 #(
      .Width(Width)
  ) u_prim_and2 (
      .in0_i(data_a[Width-1:0]),
      .in1_i(data_b[Width-1:0]),
      .out_o(var_out_not_removed[1])
  );
  prim_xor2 #(
      .Width(Width)
  ) u_prim_xor2 (
      .in0_i(data_a[Width-1:0]),
      .in1_i(data_b[Width-1:0]),
      .out_o(var_out_not_removed[2])
  );
  prim_xnor2 #(
      .Width(Width)
  ) u_prim_xnor2 (
      .in0_i(data_a[Width-1:0]),
      .in1_i(data_b[Width-1:0]),
      .out_o(var_out_not_removed[3])
  );
  prim_flop #(
      .Width(Width)
  ) u_prim_flop (
      .clk_i (clk_i),
      .rst_ni(rst_ni),
      .d_i   (data_a[Width-1:0]),
      .q_o   (var_out_not_removed[4])
  );
  prim_flop_en #(
      .Width(Width)
  ) u_prim_flop_en (
      .clk_i (clk_i),
      .rst_ni(rst_ni),
      .en_i  (en_i),
      .d_i   (data_a[Width-1:0]),
      .q_o   (var_out_not_removed[5])
  );
  prim_flop_no_rst #(
      .Width(Width)
  ) u_prim_flop_no_rst (
      .clk_i(clk_i),
      .d_i  (data_a[Width-1:0]),
      .q_o  (var_out_not_removed[6])
  );

  assign test_var_o = ^var_out_not_removed;

  ///////////////////////////////////////////////
  // Test 5: mubi4_sender with constant inputs //
  ///////////////////////////////////////////////
  // Constant mubi signals cannot be used to perform optimizations at the output
  // The following size_only cells are expected:
  // 9*4 size_only_buf
  // 4*6 size_only_flop

  mubi4_t [NumSender-1:0] mubi4_true_out;
  mubi4_t [NumSender-1:0] mubi4_false_out;
  mubi4_t [NumSender-1:0] mubi4_var_out;

  prim_mubi4_sender #(
    .AsyncOn(0),
    .EnSecBuf(0)
  ) u_mubi4_sender_true0 (
    .clk_i (clk_i),
    .rst_ni(rst_ni),
    .mubi_i(MuBi4True),
    .mubi_o(mubi4_true_out[0])
  );

  prim_mubi4_sender #(
    .AsyncOn(0),
    .EnSecBuf(0)
  ) u_mubi4_sender_false0 (
    .clk_i (clk_i),
    .rst_ni(rst_ni),
    .mubi_i(MuBi4False),
    .mubi_o(mubi4_false_out[0])
  );

  prim_mubi4_sender #(
    .AsyncOn(0),
    .EnSecBuf(0)
  ) u_mubi4_sender_var0 (
    .clk_i (clk_i),
    .rst_ni(rst_ni),
    .mubi_i(mubi4_bool_to_mubi(data_a_i[0])),
    .mubi_o(mubi4_var_out[0])
  );

  prim_mubi4_sender #(
    .AsyncOn(1),
    .EnSecBuf(0)
  ) u_mubi4_sender_true1 (
    .clk_i (clk_i),
    .rst_ni(rst_ni),
    .mubi_i(MuBi4True),
    .mubi_o(mubi4_true_out[1])
  );

  prim_mubi4_sender #(
    .AsyncOn(1),
    .EnSecBuf(0)
  ) u_mubi4_sender_false1 (
    .clk_i (clk_i),
    .rst_ni(rst_ni),
    .mubi_i(MuBi4False),
    .mubi_o(mubi4_false_out[1])
  );

  prim_mubi4_sender #(
    .AsyncOn(1),
    .EnSecBuf(0)
  ) u_mubi4_sender_var1 (
    .clk_i (clk_i),
    .rst_ni(rst_ni),
    .mubi_i(mubi4_bool_to_mubi(data_a_i[1])),
    .mubi_o(mubi4_var_out[1])
  );

  prim_mubi4_sender #(
    .AsyncOn(0),
    .EnSecBuf(1)
  ) u_mubi4_sender_true2 (
    .clk_i (clk_i),
    .rst_ni(rst_ni),
    .mubi_i(MuBi4False),
    .mubi_o(mubi4_true_out[2])
  );

  prim_mubi4_sender #(
    .AsyncOn(0),
    .EnSecBuf(1)
  ) u_mubi4_sender_false2 (
    .clk_i (clk_i),
    .rst_ni(rst_ni),
    .mubi_i(MuBi4False),
    .mubi_o(mubi4_false_out[2])
  );

  prim_mubi4_sender #(
    .AsyncOn(0),
    .EnSecBuf(1)
  ) u_mubi4_sender_var2 (
    .clk_i (clk_i),
    .rst_ni(rst_ni),
    .mubi_i(mubi4_bool_to_mubi(data_a_i[2])),
    .mubi_o(mubi4_var_out[2])
  );

  prim_mubi4_sender #(
    .AsyncOn(1),
    .EnSecBuf(1)
  ) u_mubi4_sender_true3 (
    .clk_i (clk_i),
    .rst_ni(rst_ni),
    .mubi_i(MuBi4False),
    .mubi_o(mubi4_true_out[3])
  );

  prim_mubi4_sender #(
    .AsyncOn(1),
    .EnSecBuf(1)
  ) u_mubi4_sender_false3 (
    .clk_i (clk_i),
    .rst_ni(rst_ni),
    .mubi_i(MuBi4False),
    .mubi_o(mubi4_false_out[3])
  );

  prim_mubi4_sender #(
    .AsyncOn(1),
    .EnSecBuf(1)
  ) u_mubi4_sender_var3 (
    .clk_i (clk_i),
    .rst_ni(rst_ni),
    .mubi_i(mubi4_bool_to_mubi(data_a_i[3])),
    .mubi_o(mubi4_var_out[3])
  );

  // none of these bool_out can be tied directly to low/high
  for (genvar idx = 0; idx < NumSender; idx++) begin : g_out
    assign test_mubi_bool_out_o[idx][0]  = mubi4_test_true_strict(mubi4_true_out[idx]);
    assign test_mubi_bool_out_o[idx][1]  = mubi4_test_true_loose(mubi4_true_out[idx]);
    assign test_mubi_bool_out_o[idx][2]  = mubi4_test_false_strict(mubi4_true_out[idx]);
    assign test_mubi_bool_out_o[idx][3]  = mubi4_test_false_loose(mubi4_true_out[idx]);
    assign test_mubi_bool_out_o[idx][4]  = mubi4_test_true_strict(mubi4_false_out[idx]);
    assign test_mubi_bool_out_o[idx][5]  = mubi4_test_true_loose(mubi4_false_out[idx]);
    assign test_mubi_bool_out_o[idx][6]  = mubi4_test_false_strict(mubi4_false_out[idx]);
    assign test_mubi_bool_out_o[idx][7]  = mubi4_test_false_loose(mubi4_false_out[idx]);
    assign test_mubi_bool_out_o[idx][8]  = mubi4_test_true_strict(mubi4_var_out[idx]);
    assign test_mubi_bool_out_o[idx][9]  = mubi4_test_true_loose(mubi4_var_out[idx]);
    assign test_mubi_bool_out_o[idx][10] = mubi4_test_false_strict(mubi4_var_out[idx]);
    assign test_mubi_bool_out_o[idx][11] = mubi4_test_false_loose(mubi4_var_out[idx]);
  end

  //////////////////////////////
  // Test 6: mubi_sync_copies //
  //////////////////////////////
  // These gates cannot be removed
  // The following size_only cells are expected:
  // 2*2*4 size_only_buf
  // 4*2 size_only_flop

  localparam int unsigned NumCopies = 2;

  mubi4_t [NumCopies-1:0] mubi_var0, mubi_var1;
  mubi4_t [1:0] mubi_var_comp;

  prim_mubi4_sync #(
    .NumCopies(NumCopies),
    .AsyncOn(0)
  ) u_prim_mubi4_sync0 (
    .clk_i (clk_i),
    .rst_ni(rst_ni),
    .mubi_i(mubi4_bool_to_mubi(data_a_i[0])),
    .mubi_o(mubi_var0)
  );

  prim_mubi4_sync #(
    .NumCopies(NumCopies),
    .AsyncOn(1)
  ) u_prim_mubi4_sync1 (
    .clk_i (clk_i),
    .rst_ni(rst_ni),
    .mubi_i(mubi4_bool_to_mubi(data_b_i[0])),
    .mubi_o(mubi_var1)
  );

  // These comparisons can be simplified to just mubi_var0/1 but the sythesizer is not allowed to
  // perform the optimizations
  assign mubi_var_comp[0] = mubi4_or_hi (mubi_var0[0], mubi_var0[1]);
  assign mubi_var_comp[1] = mubi4_and_hi(mubi_var1[0], mubi_var1[1]);

  assign test_mubi_out_o[0] = mubi4_test_false_loose(mubi_var_comp[0]);
  assign test_mubi_out_o[1] = mubi4_test_true_loose(mubi_var_comp[1]);

  ///////////////////////////////
  // Test 7: test_clock_gating //
  ///////////////////////////////
  // clock gate cannot be removed
  // The following size_only cells are expected:
  // 2 size_only_clock_gating
  // 2 size_only_clock_mux2
  // 2*2*8 size_only_flop

  logic [1:0]             clk, clk_muxed;

  // cannot be removed even though clock is always on/off
  prim_clock_gating u_prim_clk_gate_const0 (
    .clk_i    (clk_i),
    .en_i     (1'b0),
    .test_en_i(1'b0),
    .clk_o    (clk[0])
  );
  prim_clock_gating u_prim_clk_gate_const1 (
    .clk_i    (clk_i),
    .en_i     (1'b1),
    .test_en_i(1'b0),
    .clk_o    (clk[1])
  );

  // mux cannot be removed even though select is constant
  prim_clock_mux2 u_prim_clock_mux_const0 (
    .clk0_i(clk_i),
    .clk1_i(1'b0),
    .sel_i (1'b0),
    .clk_o (clk_muxed[0])
  );

  // mux cannot be removed even though select and clkinput is constant
  prim_clock_mux2 u_prim_clock_mux_const1 (
    .clk0_i(clk_i),
    .clk1_i(1'b0),
    .sel_i (1'b1),
    .clk_o (clk_muxed[1])
  );

  for (genvar idx = 0; idx < 2; idx++) begin : g_flops
    prim_flop #(
      .Width(Width)
    ) u_prim_flop_clk_const (
      .clk_i (clk[idx]),
      .rst_ni(rst_ni),
      .d_i   (data_a[Width-1:0]),
      .q_o   (test_clk_gen_o[0+2*idx])
    );
    prim_flop #(
      .Width(Width)
    ) u_prim_flop_clk_muxed (
      .clk_i (clk_muxed[idx]),
      .rst_ni(rst_ni),
      .d_i   (data_b[Width-1:0]),
      .q_o   (test_clk_gen_o[1+2*idx])
    );
  end

  //////////////////////////
  // Test 8: lc_sync test //
  //////////////////////////
  // All copies must be present and output logic cannot be optimized
  // The following size_only cells are expected:
  // 2*2*4 size_only_buf
  // 4*2 size_only_flop

  localparam int unsigned NumCopiesLc = 2;
  import lc_ctrl_pkg::*;

  lc_tx_t [NumCopiesLc-1:0] lc_var0, lc_var1;
  lc_tx_t [1:0]             lc_var_comp;

  prim_lc_sync #(
    .NumCopies(NumCopiesLc),
    .AsyncOn(0)
  ) u_prim_lc_sync0 (
    .clk_i  (clk_i),
    .rst_ni (rst_ni),
    .lc_en_i(lc_tx_bool_to_lc_tx(data_a_i[0])),
    .lc_en_o(lc_var0)
  );

  prim_lc_sync #(
    .NumCopies(NumCopiesLc),
    .AsyncOn(1)
  ) u_prim_lc_sync1 (
    .clk_i  (clk_i),
    .rst_ni (rst_ni),
    .lc_en_i(lc_tx_bool_to_lc_tx(data_b_i[0])),
    .lc_en_o(lc_var1)
  );

  // These comparisons can be simplified to just lc_var0/1 but the sythesizer is not allowed to
  // perform the optimizations
  assign lc_var_comp[0] = lc_tx_or_hi (lc_var0[0], lc_var0[1]);
  assign lc_var_comp[1] = lc_tx_and_hi(lc_var1[0], lc_var1[1]);

  assign test_lc_out_o[0] = lc_tx_test_false_loose(lc_var_comp[0]);
  assign test_lc_out_o[1] = lc_tx_test_true_loose(lc_var_comp[1]);

  ////////////////////////////
  // Test 9: lc_sender test //
  ////////////////////////////
  // Send different lc_en signals through prim_sender and perform constant comparisons
  // Output comparisons cannot be removed and output xor tree must remain
  // The following size_only cells are expected:
  // 3*4 size_only_buf
  // 3*4 size_only_flop

  lc_tx_t [NumSenderLc-1:0] lc_on_out;
  lc_tx_t [NumSenderLc-1:0] lc_off_out;
  lc_tx_t [NumSenderLc-1:0] lc_var_out;

  prim_lc_sender #(
    .AsyncOn(0)
  ) u_lc_sender_on0 (
    .clk_i  (clk_i),
    .rst_ni (rst_ni),
    .lc_en_i(On),
    .lc_en_o(lc_on_out[0])
  );

  prim_lc_sender #(
    .AsyncOn(0)
  ) u_lc_sender_off0 (
    .clk_i  (clk_i),
    .rst_ni (rst_ni),
    .lc_en_i(Off),
    .lc_en_o(lc_off_out[0])
  );

  prim_lc_sender #(
    .AsyncOn(0)
  ) u_lc_sender_var0 (
    .clk_i  (clk_i),
    .rst_ni (rst_ni),
    .lc_en_i(lc_tx_bool_to_lc_tx(data_a_i[0])),
    .lc_en_o(lc_var_out[0])
  );

  prim_lc_sender #(
    .AsyncOn(1)
  ) u_lc_sender_on1 (
    .clk_i  (clk_i),
    .rst_ni (rst_ni),
    .lc_en_i(On),
    .lc_en_o(lc_on_out[1])
  );

  prim_lc_sender #(
    .AsyncOn(1)
  ) u_lc_sender_off1 (
    .clk_i  (clk_i),
    .rst_ni (rst_ni),
    .lc_en_i(Off),
    .lc_en_o(lc_off_out[1])
  );

  prim_lc_sender #(
    .AsyncOn(1)
  ) u_lc_sender_var1 (
    .clk_i  (clk_i),
