module leverages 4bit SBoxes from the PRINCE cipher, and interleaves them with registers,
// resulting in a split of around 50/50 between logic and sequential cells.
//
// This generator has been tested with 32bit wide data, and produces the following results:
//
// -------------+-----------+----------
// requested GE | actual GE | GE error
// -------------+-----------+----------
// 500          |  483      |  -17
// 1000         |  964      |  -36
// 1500         |  1447     |  -53
// 2500         |  2892     |  392
// 5000         |  5299     |  299
// 7500         |  8030     |  530
// 10000        |  10393    |  393
// 15000        |  15575    |  575
// 25000        |  26422    |  1422
// 50000        |  52859    |  2859
// 100000       |  105270   |  5270
//
// Note that the generator is not very accurate for smaller gate counts due to the generate loop
// granularity. Hence, do not use for fever than 500 GE.
//
// If valid_i constantly set to 1'b1, the gate generator produces around 2.5% smaller designs for
// the configurations listed in the table above.

`include "prim_assert.sv"
module prim_gate_gen #(
  parameter int DataWidth = 32,
  parameter int NumGates = 1000
) (
  input                        clk_i,
  input                        rst_ni,

  input                        valid_i,
  input        [DataWidth-1:0] data_i,
  output logic [DataWidth-1:0] data_o,
  output                       valid_o
);

  /////////////////////////////////////
  // Local parameters and assertions //
  /////////////////////////////////////

  // technology specific tuning, do not modify.
  // an inner round is comprised of a 2bit rotation, followed by a 4bit SBox Layer.
  localparam int NumInnerRounds = 2;
  localparam int GatesPerRound  = DataWidth * 14;
  // an outer round consists of NumInnerRounds, followed by a register.
  localparam int NumOuterRounds = (NumGates + GatesPerRound / 2) / GatesPerRound;

  // do not use for fewer than 500 GE
  `ASSERT(MinimumNumGates_A, NumGates >= 500)
  `ASSERT(DataMustBeMultipleOfFour_A, DataWidth % 4 == 0)

  /////////////////////
  // Generator Loops //
  /////////////////////

  logic [NumOuterRounds-1:0][DataWidth-1:0] regs_d, regs_q;
  logic [NumOuterRounds-1:0] valid_d, valid_q;

  for (genvar k = 0; k < NumOuterRounds; k++) begin : gen_outer_round

    logic [NumInnerRounds:0][DataWidth-1:0] inner_data;

    if (k==0) begin : gen_first
      assign inner_data[0] = data_i;
      assign valid_d[0]    = valid_i;
    end else begin : gen_others
      assign inner_data[0] = regs_q[k-1];
      assign valid_d[k]    = valid_q[k-1];
    end

    for (genvar l = 0; l < NumInnerRounds; l++) begin : gen_inner
      // 2bit rotation + sbox layer
      assign inner_data[l+1] = prim_cipher_pkg::sbox4_32bit({inner_data[l][1:0],
                                                             inner_data[l][DataWidth-1:2]},
                                                             prim_cipher_pkg::PRINCE_SBOX4);
    end

    assign regs_d[k] = inner_data[NumInnerRounds];
  end

  always_ff @(posedge clk_i or negedge rst_ni) begin : p_regs
    if (!rst_ni) begin
      regs_q <= '0;
      valid_q <= '0;
    end else begin
      valid_q <= valid_d;
      for (int k = 0; k < NumOuterRounds; k++) begin
        if (valid_d[k]) begin
          regs_q[k] <= regs_d[k];
        end
      end
    end
  end

  assign data_o = regs_q[NumOuterRounds-1];
  assign valid_o = valid_q[NumOuterRounds-1];

endmodule

module is instantiates a hand-picked flop cell for each bit in the
// multibit signal such that tools do not optimize the multibit encoding.

`include "prim_assert.sv"

module prim_mubi20_sender
  import prim_mubi_pkg::*;
#(
  // This flops the output if set to 1.
  // In special cases where the sender is in the same clock domain as the receiver,
  // this can be set to 0. However, it is recommended to leave this at 1.
  parameter bit AsyncOn = 1,
  // Enable anchor buffer
  parameter bit EnSecBuf = 0,
  // Reset value for the sender flops
  parameter mubi20_t ResetValue = MuBi20False
) (
  input          clk_i,
  input          rst_ni,
  input  mubi20_t mubi_i,
  output mubi20_t mubi_o
);

  logic [MuBi20Width-1:0] mubi, mubi_int, mubi_out;
  assign mubi = MuBi20Width'(mubi_i);

  // first generation block decides whether a flop should be present
  if (AsyncOn) begin : gen_flops
    prim_flop #(
      .Width(MuBi20Width),
      .ResetValue(MuBi20Width'(ResetValue))
    ) u_prim_flop (
      .clk_i,
      .rst_ni,
      .d_i   ( mubi     ),
      .q_o   ( mubi_int )
    );
  end else begin : gen_no_flops
    assign mubi_int = mubi;

    // This unused companion logic helps remove lint errors
    // for modules where clock and reset are used for assertions only
    // This logic will be removed for synthesis since it is unloaded.
    mubi20_t unused_logic;
    always_ff @(posedge clk_i or negedge rst_ni) begin
      if (!rst_ni) begin
         unused_logic <= MuBi20False;
      end else begin
         unused_logic <= mubi_i;
      end
    end
  end

  // second generation block determines output buffer type
  // 1. If EnSecBuf -> always leads to a sec buffer regardless of first block
  // 2. If not EnSecBuf and not AsyncOn -> use normal buffer
  // 3. If not EnSecBuf and AsyncOn -> feed through
  if (EnSecBuf) begin : gen_sec_buf
    prim_sec_anchor_buf #(
      .Width(20)
    ) u_prim_sec_buf (
      .in_i(mubi_int),
      .out_o(mubi_out)
    );
  end else if (!AsyncOn) begin : gen_prim_buf
    prim_buf #(
      .Width(20)
    ) u_prim_buf (
      .in_i(mubi_int),
      .out_o(mubi_out)
    );
  end else begin : gen_feedthru
    assign mubi_out = mubi_int;
  end

  assign mubi_o = mubi20_t'(mubi_out);

  ////////////////
  // Assertions //
  ////////////////

  // The outputs should be known at all times.
  `ASSERT_KNOWN(OutputsKnown_A, mubi_o)

endmodule

module encodes a single bit signal to a differentially encoded signal.
//
// In case the differential pair crosses an asynchronous boundary, it has
// to be re-synchronized to the local clock.

module prim_diff_encode (
  input logic  clk_i,
  input logic  rst_ni,
  // Single line input signal
  input logic  req_i,
  // Output diff pair
  output logic diff_po,
  output logic diff_no
);
  // Buff the input signal to avoid any optimization
  logic req;
  prim_sec_anchor_buf #(
    .Width(1)
  ) u_prim_buf_in_req (
    .in_i(req_i),
    .out_o(req)
  );

  // Differentially encode input
  logic diff_p, diff_n;
  assign diff_p = req;
  assign diff_n = ~req;

  // This prevents further tool optimizations of the differential signal.
  prim_sec_anchor_buf #(
    .Width(2)
  ) u_prim_buf_ack (
    .in_i({diff_n, diff_p}),
    .out_o({diff_n_buf, diff_p_buf})
  );

  // Flop differentially encoded signal at the output
  prim_flop #(
    .Width(1),
    .ResetValue(1'b0)
  ) u_diff_p (
    .clk_i,
    .rst_ni,
    .d_i   ( diff_p_buf ),
    .q_o   ( diff_po    )
  );

  prim_flop #(
    .Width(1),
    .ResetValue(1'b1)
  ) u_diff_n (
    .clk_i,
    .rst_ni,
    .d_i   ( diff_n_buf ),
    .q_o   ( diff_no    )
  );
endmodule

module prim_ascon_duplex
  import prim_ascon_pkg::*;
 (
  input logic clk_i,
  input logic rst_ni,

  input duplex_variant_e ascon_variant,
  input duplex_op_e ascon_operation,

  input  logic start_i,
  output logic done_o,

  output prim_mubi_pkg::mubi4_t idle_o,

  // It is assumed that no_ad, no_msg, key, and nonce are always
  // valid and constant, when the cipher is triggered by the start command
  input prim_mubi_pkg::mubi4_t no_ad_i,
  input prim_mubi_pkg::mubi4_t no_msg_i,

  input logic [127:0] key_i,
  input logic [127:0] nonce_i,

  // Cipher Input Port
  input  logic [127:0]          data_in_i,
  input  logic   [4:0]          data_in_valid_bytes_i,
  input  prim_mubi_pkg::mubi4_t last_block_ad_i,
  input  prim_mubi_pkg::mubi4_t last_block_msg_i,
  input  logic                  data_in_valid_i,
  output logic                  data_in_ready_o,

  // Cipher Output Port
  output logic [127:0] data_out_o,
  input  logic         data_out_ready_i,
  output logic         data_out_valid_o,

  output logic [127:0] tag_out_o,
  output logic         tag_out_valid_o,

  output duplex_fsm_state_e fsm_state_o,

  output logic err_o
);

// TODO: Add backpressure check
logic unused_data_out_ready_i;
assign unused_data_out_ready_i = data_out_ready_i;

logic round_count_error;
logic sparse_fsm_error;

logic set_round_counter;
logic inc_round_counter;

logic [4:0][63:0] ascon_state_q, ascon_state_d;

// Ascon's 320 bit state
always_ff @(posedge clk_i or negedge rst_ni) begin : ascon_state_reg
  if (!rst_ni) begin
    ascon_state_q <= '0;
  end else begin
    ascon_state_q <= ascon_state_d;
  end
end

logic [319:0] state_to_round;
logic [319:0] state_from_round;

logic [4:0][63:0] round_to_mux;
assign round_to_mux = state_from_round;

duplex_fsm_state_e fsm_state_d, fsm_state_q;
perm_offset_e perm_offset;

assign fsm_state_o = fsm_state_q;

logic  [63:0] iv;
assign iv = (ascon_variant == ASCON_128) ? IV_128 : IV_128A;

// internal combinatorial signals
prim_mubi_pkg::mubi4_t complete_block;

// TODO add a check what to do, if data_in_valid_bytes_i is greater than blocksize
assign complete_block =  (ascon_variant == ASCON_128  && data_in_valid_bytes_i ==  8)
                       ||(ascon_variant == ASCON_128A && data_in_valid_bytes_i == 16) ?
                          prim_mubi_pkg::MuBi4True : prim_mubi_pkg::MuBi4False;

// Padding:
// 1) Associated Data
//    a) empty AD: No padding, AD-processing phase is skipped!
//    b) incomplete last block: A 10* padding is added to the input data.
//       The padded associated data is XORed to the state.
//    c) complete last block: No padding to the input, but an additional state in the FSM
//       is used to perform the padding. A 10+ block is XORed to the state.
// 2) Encryption:
//    a) empty or incomplete last block: A 10* padding is added to the input data.
//       The padded associated data is XORed blockwise.
//    b) complete last block: No padding to the input, but an additional state in the FSM
//       is used to perform the padding. A 10+ block is XORed to the sate.
// 3) Decryption:
//    a) empty or incomplete last block: The padded (output) PLAINTEXT is XORed to the state.
//       This is equivalent to:
//       The unpadded part of the Ciphertext replaces the corresponding part of S_r
//       The remaining part of S_r is Xored with 10*.
//    b) complete last block: No padding to the input, but an additional state in the FSM
//       is used to perform the padding. A 10+ block is XORed to the state,

// Padding logic
logic [127:0] empty_padding;
assign empty_padding = get_padding_mask(5'b00000);

logic [127:0] valid_bytes_bit_mask;
assign valid_bytes_bit_mask = bin2thermo(data_in_valid_bytes_i);

logic [127:0] padding_byte_bit_mask;
assign padding_byte_bit_mask = get_padding_mask(data_in_valid_bytes_i);

logic [127:0] data_in_valid_bytes;
assign data_in_valid_bytes = data_in_i & valid_bytes_bit_mask;

// data output
logic  [127:0] data_out;
assign data_out = (data_in_i ^ {ascon_state_q[0], ascon_state_q[1]}) & valid_bytes_bit_mask;

logic [127:0] data_in_padded;
logic [127:0] data_out_padded; // is only used internally for decryption.

// For BOTH encryption AND decryption the PLAINTEXT is XORed to the state!
// For encryption this is straight forward: S_r = S_r XOR P
// For decryption this means: S_r = S_r XOR P = S_r XOR (S_r XOR C) = C
// Thus the ciphertext replaces the rate. However, we cannot simply implement
// S_r = C, because this does not work for incomplete blocks, where only a part
// of the rate is replaced by C and the other part remains:
// S_r = S_l || S_(r-l) = C_l || S_(r-l)
// Therefore, it is easier to always XOR the padded plaintext

always_comb begin
  if (prim_mubi_pkg::mubi4_test_true_strict(complete_block)) begin
      data_in_padded = data_in_valid_bytes;
      data_out_padded = data_out;
    end else begin
      data_in_padded = data_in_valid_bytes | padding_byte_bit_mask;
      data_out_padded = data_out | padding_byte_bit_mask;
  end
end

// TODO  add blinding
assign data_out_o  = data_out;
assign  tag_out_o  = ({ascon_state_q[3], ascon_state_q[4]} ^ key_i);

// Due to Ascon's round constants the current_round
// contains an offset:
// for P12 we count: from 0 to 11 = 12 rounds,
// for P8  we count: from 4 to 11 =  8 rounds,
// for P6  we count: from 5 to 11 =  6 rounds
logic [AsconRoundCountW-1:0] current_round;

prim_count #(
    .Width(AsconRoundCountW)
) u_round_counter (
    .clk_i,
    .rst_ni,
    .clr_i(1'b0),
    .set_i(set_round_counter),
    .set_cnt_i(perm_offset),
    .incr_en_i(inc_round_counter),
    .decr_en_i(1'b0),
    .step_i(AsconRoundCountW'(1)),
    .commit_i(1'b1),
    .cnt_o(current_round),
    .cnt_after_commit_o(),
    .err_o(round_count_error)
  );

// Duplexswitch muxes
// Selects data input source
padding_mux_e sel_padding;

// Main multiplexer per word
ascon_word_mux_e sel_mux_word0;
ascon_word_mux_e sel_mux_word1;
ascon_word_mux_e sel_mux_word2;
ascon_word_mux_e sel_mux_word3;
ascon_word_mux_e sel_mux_word4;

// Multiplexer before XOR
word_low_key_hi_mux_e sel_mux_key_word1;
key_hi_low_mux_e      sel_mux_key_word2;
key_hi_low_mux_e      sel_mux_key_word3;

// Selects round input
ascon_round_input_mux_e sel_round_input;

// Set domain separation
logic set_dom_sep;

// Intermediate signals
logic [4:0][63:0] xor_with_state;
logic      [63:0] word4_dom_sep;
logic     [127:0] data_to_duplex;

// Enc Dec Padding Mux
always_comb begin : Padding
  unique case (sel_padding)
    DATA_IN_PAD:  data_to_duplex = data_in_padded;
    DATA_OUT_PAD: data_to_duplex = data_out_padded;
    EMPTY_PAD:    data_to_duplex = empty_padding;
    default:      data_to_duplex = empty_padding;
  endcase
end

// State input mux
always_comb begin : state_input
  unique case (sel_round_input)
    STATE:    state_to_round = ascon_state_q;
    BLINDING: state_to_round = '0;
    default:  state_to_round = '0;
  endcase
end

// Main mux word0
assign xor_with_state[0] = data_to_duplex[127:64];
always_comb begin : state_word0
  unique case (sel_mux_word0)
    INIT:    ascon_state_d[0] = iv;
    ABSORB:  ascon_state_d[0] = ascon_state_q[0] ^ xor_with_state[0];
    KEEP:    ascon_state_d[0] = ascon_state_q[0];
    ROUND:   ascon_state_d[0] = round_to_mux[0];
    default: ascon_state_d[0] = ascon_state_q[0];
  endcase
end

// Select key high or data low for XOR
always_comb begin : key_word1
  unique case (sel_mux_key_word1)
    WORD:    xor_with_state[1] = data_to_duplex[63:0];
    KEY:     xor_with_state[1] = key_i[127:64];
    default: xor_with_state[1] = key_i[127:64];
  endcase
end

// Main mux word1
always_comb begin : state_word1
  unique case (sel_mux_word1)
    INIT:    ascon_state_d[1] = key_i[127:64];
    ABSORB:  ascon_state_d[1] = ascon_state_q[1] ^ xor_with_state[1];
    KEEP:    ascon_state_d[1] = ascon_state_q[1];
    ROUND:   ascon_state_d[1] = round_to_mux[1];
    default: ascon_state_d[1] = ascon_state_q[1];
  endcase
end

// Select key high or low for XOR
always_comb begin : key_word2
  unique case (sel_mux_key_word2)
    KEY_LOW: xor_with_state[2] = key_i[63:0];
    KEY_HI:  xor_with_state[2] = key_i[127:64];
    default: xor_with_state[2] = key_i[127:64];
  endcase
end

// Main mux word2
always_comb begin : state_word2
  unique case (sel_mux_word2)
    INIT:    ascon_state_d[2] = key_i[63:0];
    ABSORB:  ascon_state_d[2] = ascon_state_q[2] ^ xor_with_state[2];
    KEEP :   ascon_state_d[2] = ascon_state_q[2];
    ROUND:   ascon_state_d[2] = round_to_mux[2];
    default: ascon_state_d[2] = ascon_state_q[2];
  endcase
end

// Select key high or low for XOR
always_comb begin : key_word3
  unique case (sel_mux_key_word3)
    KEY_LOW: xor_with_state[3] = key_i[63:0];
    KEY_HI:  xor_with_state[3] = key_i[127:64];
    default: xor_with_state[3] = key_i[127:64];
  endcase
end

// Main mux word3
always_comb begin : state_word3
  unique case (sel_mux_word3)
    INIT:    ascon_state_d[3] = nonce_i[127:64];
    ABSORB:  ascon_state_d[3] = ascon_state_q[3] ^ xor_with_state[3];
    KEEP:    ascon_state_d[3] = ascon_state_q[3];
    ROUND:   ascon_state_d[3] = round_to_mux[3];
    default: ascon_state_d[3] = ascon_state_q[3];
  endcase
end

// Set domain separation bit
assign word4_dom_sep = {ascon_state_q[4][63:1], ascon_state_q[4][0] ^ set_dom_sep};
// For word 4 only the lower part of the key can be xored to the state
assign xor_with_state[4] = key_i[63:0];

// Main mux word4
always_comb begin : state_word4
  unique case (sel_mux_word4)
    INIT:    ascon_state_d[4] = nonce_i[63:0];
    ABSORB:  ascon_state_d[4] = word4_dom_sep ^ xor_with_state[4];
    KEEP:    ascon_state_d[4] = word4_dom_sep;
    ROUND:   ascon_state_d[4] = round_to_mux[4];
    default: ascon_state_d[4] = word4_dom_sep;
  endcase
end

always_comb begin : p_fsm
  // Default assignments
  fsm_state_d = fsm_state_q;
  data_in_ready_o = 1'b0;
  data_out_valid_o = 1'b0;
  tag_out_valid_o = 1'b0;
  sparse_fsm_error = 1'b0;
  set_round_counter = 1'b0;
  inc_round_counter = 1'b0;
  perm_offset = P12;
  done_o = 1'b0;
  idle_o = prim_mubi_pkg::MuBi4False;

  // Default: Don't update state
  set_dom_sep   = 1'b0;
  sel_mux_word0 = KEEP;
  sel_mux_word1 = KEEP;
  sel_mux_word2 = KEEP;
  sel_mux_word3 = KEEP;
  sel_mux_word4 = KEEP;

  sel_mux_key_word3 = KEY_HI;
  sel_mux_key_word2 = KEY_LOW;
  sel_mux_key_word1 = KEY;

  sel_padding = EMPTY_PAD;

  sel_round_input = BLINDING;

  unique case (fsm_state_q)
    Idle: begin
      idle_o = prim_mubi_pkg::MuBi4True;
      if (start_i) begin
        fsm_state_d = Init;
      end
    end
    Init: begin
      sel_mux_word0 = INIT;
      sel_mux_word1 = INIT;
      sel_mux_word2 = INIT;
      sel_mux_word3 = INIT;
      sel_mux_word4 = INIT;
      fsm_state_d = PermInit;
      perm_offset = P12;
      set_round_counter = 1'b1;
    end
    PermInit: begin
      sel_round_input = STATE;
      sel_mux_word0 = ROUND;
      sel_mux_word1 = ROUND;
      sel_mux_word2 = ROUND;
      sel_mux_word3 = ROUND;
      sel_mux_word4 = ROUND;
      if (current_round == ROUND_MAX) begin
        fsm_state_d = Xor0Key;
      end else begin
        inc_round_counter = 1'b1;
      end
    end
    Xor0Key: begin
      sel_mux_word3 = ABSORB;
      sel_mux_key_word3 = KEY_HI;
      sel_mux_word4 = ABSORB;
      if (prim_mubi_pkg::mubi4_test_true_strict(no_ad_i)) begin
        fsm_state_d = XorDomSep;
      end else begin
        fsm_state_d = AbsorbAD;
      end
    end
    AbsorbAD: begin
      // There will be AD, otherwise we wouldn't be in this state/path
      data_in_ready_o = 1'b1;
      if (data_in_valid_i) begin
        sel_mux_word0 = ABSORB;
        sel_padding = DATA_IN_PAD;
        if (ascon_variant == ASCON_128A) begin
          sel_mux_word1 = ABSORB;
          sel_mux_key_word1 = WORD;
        end
        if (prim_mubi_pkg::mubi4_test_true_strict(last_block_ad_i)) begin
          if (prim_mubi_pkg::mubi4_test_true_strict(complete_block)) begin
            fsm_state_d = PermADEmpty;
          end else begin
            fsm_state_d = PermADLast;
          end
        end else begin // there are more blocks to come
          fsm_state_d = PermAD;
        end
      end
      if (ascon_variant == ASCON_128) begin
        perm_offset = P6;
      end else begin //ASCON_128A
        perm_offset = P8;
      end
      set_round_counter = 1'b1;
    end
    PermAD: begin
      sel_round_input = STATE;
      sel_mux_word0 = ROUND;
      sel_mux_word1 = ROUND;
      sel_mux_word2 = ROUND;
      sel_mux_word3 = ROUND;
      sel_mux_word4 = ROUND;
      if (current_round == ROUND_MAX) begin
        fsm_state_d = AbsorbAD;
      end else begin
        inc_round_counter = 1'b1;
      end
    end
    PermADLast: begin
      sel_round_input = STATE;
      sel_mux_word0 = ROUND;
      sel_mux_word1 = ROUND;
      sel_mux_word2 = ROUND;
      sel_mux_word3 = ROUND;
      sel_mux_word4 = ROUND;
      if (current_round == ROUND_MAX) begin
        fsm_state_d = XorDomSep;
      end else begin
        inc_round_counter = 1'b1;
      end
    end
    PermADEmpty: begin
      sel_round_input = STATE;
      sel_mux_word0 = ROUND;
      sel_mux_word1 = ROUND;
      sel_mux_word2 = ROUND;
      sel_mux_word3 = ROUND;
      sel_mux_word4 = ROUND;
      if (current_round == ROUND_MAX) begin
        fsm_state_d = AbsorbADEmpty;
      end else begin
        inc_round_counter = 1'b1;
      end
    end
    AbsorbADEmpty: begin
      sel_mux_word0 = ABSORB;
      sel_padding = EMPTY_PAD;
      fsm_state_d = PermADLast;
      if (ascon_variant == ASCON_128) begin
        perm_offset = P6;
      end else begin //ASCON_128A
        perm_offset = P8;
        // This should be optimized by the tool.
        // It is left here, so that the structure of the case
        // is the same as AbsorbAD.
        sel_mux_word1 = ABSORB;
        sel_padding = EMPTY_PAD;
      end
      set_round_counter = 1'b1;
    end
    XorDomSep: begin
      set_dom_sep = 1'b1;
      sel_mux_word4 = KEEP;
      if (prim_mubi_pkg::mubi4_test_true_strict(no_msg_i)) begin
        fsm_state_d = AbsorbMSGEmpty;
      end else begin
        fsm_state_d = AbsorbMSG;
      end
    end
    AbsorbMSG: begin
      data_in_ready_o = 1'b1;
      if (data_in_valid_i) begin
        data_out_valid_o = 1'b1;
        if (ascon_operation == ASCON_ENC) begin
          sel_mux_word0 = ABSORB;
          sel_padding = DATA_IN_PAD;
          if (ascon_variant == ASCON_128A) begin
            sel_mux_word1 = ABSORB;
          end
        end else begin // ASCON_DEC
          sel_mux_word0 = ABSORB;
          sel_padding = DATA_OUT_PAD;
          if (ascon_variant == ASCON_128A) begin
            sel_mux_word1 = ABSORB;
            sel_mux_key_word1 = WORD;
          end
        end
        if (prim_mubi_pkg::mubi4_test_true_strict(last_block_msg_i)) begin
          if (prim_mubi_pkg::mubi4_test_true_strict(complete_block)) begin // we need extra padding
            fsm_state_d = PermMSGEmpty;
          end else begin // padding is done on the fly
            fsm_state_d = XorKey0;
          end
        end else begin
          fsm_state_d = PermMSG;
        end
      end

      if (ascon_variant == ASCON_128) begin
        perm_offset = P6;
      end else begin //ASCON_128A
        perm_offset = P8;
      end
      set_round_counter = 1'b1;
    end
    PermMSG: begin
      sel_round_input = STATE;
      sel_mux_word0 = ROUND;
      sel_mux_word1 = ROUND;
      sel_mux_word2 = ROUND;
      sel_mux_word3 = ROUND;
      sel_mux_word4 = ROUND;
      if (current_round == ROUND_MAX) begin
        fsm_state_d = AbsorbMSG;
      end else begin
        inc_round_counter = 1'b1;
      end
    end
    PermMSGEmpty: begin
      sel_round_input = STATE;
      sel_mux_word0 = ROUND;
      sel_mux_word1 = ROUND;
      sel_mux_word2 = ROUND;
      sel_mux_word3 = ROUND;
      sel_mux_word4 = ROUND;
      if (current_round == ROUND_MAX) begin
        fsm_state_d = AbsorbMSGEmpty;
      end else begin
        inc_round_counter = 1'b1;
      end
    end
    AbsorbMSGEmpty: begin
      // The padding for an empty block is the same for encryption and decryption.
      sel_padding = EMPTY_PAD;
      sel_mux_word0 = ABSORB;
      if (ascon_variant == ASCON_128A) begin
        // This should be optimized by the tool.
        // It is left here, so that the structure of the case
        // is the same as AbsorbAD.
        sel_mux_word1 = ABSORB;
        sel_mux_key_word1 = WORD;
      end
      fsm_state_d = XorKey0;
    end
    XorKey0: begin
      if (ascon_variant == ASCON_128) begin
        sel_mux_word1 = ABSORB;
        sel_mux_key_word1 = KEY;
        sel_mux_word2 = ABSORB;
        sel_mux_key_word2 = KEY_LOW;
      end else begin //ASCON_128a
        sel_mux_word2 = ABSORB;
        sel_mux_key_word2 = KEY_HI;
        sel_mux_word3 = ABSORB;
        sel_mux_key_word3 = KEY_LOW;
      end
      fsm_state_d = PermFinal;
      set_round_counter = 1'b1;
      perm_offset = P12;
    end
    PermFinal: begin
      sel_round_input = STATE;
      sel_mux_word0 = ROUND;
      sel_mux_word1 = ROUND;
      sel_mux_word2 = ROUND;
      sel_mux_word3 = ROUND;
      sel_mux_word4 = ROUND;
      if (current_round == ROUND_MAX) begin
        fsm_state_d = SqueezeTagXorKey;
      end else begin
        inc_round_counter = 1'b1;
      end
    end
    SqueezeTagXorKey: begin
      tag_out_valid_o = 1'b1;
      fsm_state_d = Idle;
      done_o = 1'b1;
    end
    Error: begin
      fsm_state_d = Error;
      sparse_fsm_error = 1'b1;
    end
    default: begin
      fsm_state_d = Error;
      sparse_fsm_error = 1'b1;
    end
  endcase
end

`PRIM_FLOP_SPARSE_FSM(u_state_regs, fsm_state_d, fsm_state_q, duplex_fsm_state_e, Idle)

logic mubi_error;
assign mubi_error = prim_mubi_pkg::mubi4_test_invalid(no_ad_i)
                  | prim_mubi_pkg::mubi4_test_invalid(no_msg_i)
                  | prim_mubi_pkg::mubi4_test_invalid(complete_block)
                  | prim_mubi_pkg::mubi4_test_invalid(last_block_ad_i)
                  | prim_mubi_pkg::mubi4_test_invalid(last_block_msg_i);

assign err_o = round_count_error | sparse_fsm_error | mubi_error;

prim_ascon_round u_prim_ascon_round (
  .state_o(state_from_round),
  .state_i(state_to_round),
  .rcon_i(get_ascon_rcon(current_round))
);


endmodule

module prim_secded_hamming_39_32_dec (
  input        [38:0] data_i,
  output logic [31:0] data_o,
  output logic [6:0] syndrome_o,
  output logic [1:0] err_o
);

  always_comb begin : p_encode
    // Syndrome calculation
    syndrome_o[0] = ^(data_i & 39'h0156AAAD5B);
    syndrome_o[1] = ^(data_i & 39'h029B33366D);
    syndrome_o[2] = ^(data_i & 39'h04E3C3C78E);
    syndrome_o[3] = ^(data_i & 39'h0803FC07F0);
    syndrome_o[4] = ^(data_i & 39'h1003FFF800);
    syndrome_o[5] = ^(data_i & 39'h20FC000000);
    syndrome_o[6] = ^(data_i & 39'h7FFFFFFFFF);

    // Corrected output calculation
    data_o[0] = (syndrome_o == 7'h43) ^ data_i[0];
    data_o[1] = (syndrome_o == 7'h45) ^ data_i[1];
    data_o[2] = (syndrome_o == 7'h46) ^ data_i[2];
    data_o[3] = (syndrome_o == 7'h47) ^ data_i[3];
    data_o[4] = (syndrome_o == 7'h49) ^ data_i[4];
    data_o[5] = (syndrome_o == 7'h4a) ^ data_i[5];
    data_o[6] = (syndrome_o == 7'h4b) ^ data_i[6];
    data_o[7] = (syndrome_o == 7'h4c) ^ data_i[7];
    data_o[8] = (syndrome_o == 7'h4d) ^ data_i[8];
    data_o[9] = (syndrome_o == 7'h4e) ^ data_i[9];
    data_o[10] = (syndrome_o == 7'h4f) ^ data_i[10];
    data_o[11] = (syndrome_o == 7'h51) ^ data_i[11];
    data_o[12] = (syndrome_o == 7'h52) ^ data_i[12];
    data_o[13] = (syndrome_o == 7'h53) ^ data_i[13];
    data_o[14] = (syndrome_o == 7'h54) ^ data_i[14];
    data_o[15] = (syndrome_o == 7'h55) ^ data_i[15];
    data_o[16] = (syndrome_o == 7'h56) ^ data_i[16];
    data_o[17] = (syndrome_o == 7'h57) ^ data_i[17];
    data_o[18] = (syndrome_o == 7'h58) ^ data_i[18];
    data_o[19] = (syndrome_o == 7'h59) ^ data_i[19];
    data_o[20] = (syndrome_o == 7'h5a) ^ data_i[20];
    data_o[21] = (syndrome_o == 7'h5b) ^ data_i[21];
    data_o[22] = (syndrome_o == 7'h5c) ^ data_i[22];
    data_o[23] = (syndrome_o == 7'h5d) ^ data_i[23];
    data_o[24] = (syndrome_o == 7'h5e) ^ data_i[24];
    data_o[25] = (syndrome_o == 7'h5f) ^ data_i[25];
    data_o[26] = (syndrome_o == 7'h61) ^ data_i[26];
    data_o[27] = (syndrome_o == 7'h62) ^ data_i[27];
    data_o[28] = (syndrome_o == 7'h63) ^ data_i[28];
    data_o[29] = (syndrome_o == 7'h64) ^ data_i[29];
    data_o[30] = (syndrome_o == 7'h65) ^ data_i[30];
    data_o[31] = (syndrome_o == 7'h66) ^ data_i[31];

    // err_o calc. bit0: single error, bit1: double error
    err_o[0] = syndrome_o[6];
    err_o[1] = |syndrome_o[5:0] & ~syndrome_o[6];
  end
endmodule

