module imm_gen (
    input  [31:0] inst,
    output reg [31:0] imm
);
    wire [6:0] opcode = inst[6:0];

    always @* begin
        case (opcode)
            // I-type: ADDI, LW, JALR, etc.
            7'b0010011, 7'b0000011, 7'b1100111:
                imm = {{20{inst[31]}}, inst[31:20]};
            // S-type: SW, SH, SB
            7'b0100011:
                imm = {{20{inst[31]}}, inst[31:25], inst[11:7]};
            // B-type: branches
            7'b1100011:
                imm = {{19{inst[31]}}, inst[31], inst[7], inst[30:25], inst[11:8], 1'b0};
            // U-type: LUI, AUIPC
            7'b0110111, 7'b0010111:
                imm = {inst[31:12], 12'b0};
            // J-type: JAL
            7'b1101111:
                imm = {{11{inst[31]}}, inst[31], inst[19:12], inst[20], inst[30:21], 1'b0};
            default:
                imm = 32'b0;
        endcase
    end
endmodule

module pipeline_reg #(parameter W = 32) (
    input              clk,
    input              rst,
    input              stall,
    input              flush,
    input      [W-1:0] d,
    output reg [W-1:0] q
);
    always @(posedge clk) begin
        if (rst || flush)
            q <= {W{1'b0}};
        else if (!stall)
            q <= d;
    end
endmodule

